CREATE OR REPLACE FUNCTION "public"."get_email_template_by_key"("p_key" "text") RETURNS TABLE("id" "uuid", "key" "text", "name" "text", "subject" "text", "body_html" "text", "variables" "jsonb", "is_active" boolean)
    LANGUAGE "plpgsql"
    SET "search_path" TO 'public'
