-- === MIGRATION START: 20250705000005_phase9_5_process_checkout_ledger_fixes.sql ===
-- SOURCE_PATH: C:\Users\SUACAUBA\Downloads\Project\vietsale-pro-v7\supabase\migrations\20250705000005_phase9_5_process_checkout_ledger_fixes.sql
-- SIZE_BYTES: 18237
-- SHA256: 469A016AB3CAE504C395C56925565874C3D0CD4DD1A9EFE389150680456E1E01

-- Sub-phase 9.5 follow-up: make stock/customer ledger helpers tenant-aware
-- Các bảng stock_movements và customer_payment_ledger đã có tenant_id NOT NULL,
-- nên các helper cũ sẽ lỗi khi process_checkout_tenant gọi. Cập nhật helper nhận tenant_id
-- và dùng current_tenant_id() làm fallback để giữ backward compatibility.

-- ============================================================================
-- 1. calc_qty_after_transaction: tính tồn đúng phạm vi tenant
-- ============================================================================

CREATE OR REPLACE FUNCTION public.calc_qty_after_transaction(
  p_product_id TEXT,
  p_lot_id TEXT,
  p_actual_qty NUMERIC,
  p_tenant_id UUID DEFAULT NULL
)
RETURNS NUMERIC
LANGUAGE plpgsql
STABLE SECURITY DEFINER
SET search_path = public
AS $$
DECLARE
  v_balance NUMERIC;
  v_tenant_id UUID := COALESCE(p_tenant_id, public.current_tenant_id());
BEGIN
  SELECT COALESCE(SUM(actual_qty), 0) INTO v_balance
  FROM public.stock_movements
  WHERE product_id = p_product_id
    AND lot_id IS NOT DISTINCT FROM p_lot_id
    AND is_cancelled = FALSE
    AND (v_tenant_id IS NULL OR tenant_id = v_tenant_id);
  RETURN v_balance + p_actual_qty;
END;
$$;

-- ============================================================================
-- 2. insert_stock_ledger_entry: ghi tenant_id vào stock_movements
-- ============================================================================

CREATE OR REPLACE FUNCTION public.insert_stock_ledger_entry(
  p_posting_date TIMESTAMPTZ,
  p_voucher_type TEXT,
  p_voucher_no TEXT,
  p_voucher_detail_no TEXT,
  p_product_id TEXT,
  p_lot_id TEXT,
  p_warehouse TEXT,
  p_actual_qty NUMERIC,
  p_qty_after_transaction NUMERIC,
  p_valuation_rate NUMERIC,
  p_incoming_rate NUMERIC,
  p_outgoing_rate NUMERIC,
  p_reason TEXT,
  p_is_cancelled BOOLEAN DEFAULT FALSE,
  p_tenant_id UUID DEFAULT NULL
)
RETURNS VOID
LANGUAGE plpgsql
SECURITY DEFINER
SET search_path = public
AS $$
DECLARE
  v_qty_after_transaction NUMERIC;
  v_tenant_id UUID := COALESCE(p_tenant_id, public.current_tenant_id());
BEGIN
  IF EXISTS (
    SELECT 1 FROM public.stock_movements
    WHERE voucher_type = p_voucher_type
      AND voucher_detail_no = p_voucher_detail_no
      AND is_cancelled = p_is_cancelled
      AND lot_id IS NOT DISTINCT FROM p_lot_id
      AND (v_tenant_id IS NULL OR tenant_id = v_tenant_id)
    LIMIT 1
  ) THEN
    RETURN;
  END IF;

  v_qty_after_transaction := public.calc_qty_after_transaction(p_product_id, p_lot_id, p_actual_qty, v_tenant_id);

  INSERT INTO public.stock_movements (
    posting_date, voucher_type, voucher_no, voucher_detail_no,
    product_id, lot_id, warehouse, actual_qty, qty_after_transaction,
    valuation_rate, incoming_rate, outgoing_rate, stock_value, balance_value,
    reason, is_cancelled, tenant_id
  ) VALUES (
    p_posting_date, p_voucher_type, p_voucher_no, p_voucher_detail_no,
    p_product_id, p_lot_id, COALESCE(p_warehouse, 'Kho Chính'),
    p_actual_qty, v_qty_after_transaction,
    COALESCE(p_valuation_rate, 0),
    COALESCE(p_incoming_rate, 0),
    COALESCE(p_outgoing_rate, 0),
    p_actual_qty * COALESCE(p_valuation_rate, 0),
    v_qty_after_transaction * COALESCE(p_valuation_rate, 0),
    p_reason,
    COALESCE(p_is_cancelled, FALSE),
    v_tenant_id
  );
END;
$$;

-- ============================================================================
-- 3. insert_customer_ledger_entry: ghi tenant_id vào customer_payment_ledger
-- ============================================================================

CREATE OR REPLACE FUNCTION public.insert_customer_ledger_entry(
  p_customer_id TEXT,
  p_reference_type TEXT,
  p_reference_id TEXT DEFAULT NULL,
  p_amount NUMERIC DEFAULT 0,
  p_reason TEXT DEFAULT NULL,
  p_created_by TEXT DEFAULT 'system'::TEXT,
  p_created_at TIMESTAMPTZ DEFAULT NOW(),
  p_tenant_id UUID DEFAULT NULL
)
RETURNS NUMERIC
LANGUAGE plpgsql
SECURITY DEFINER
SET search_path = public
AS $$
DECLARE
  v_balance_after NUMERIC(15,2);
  v_tenant_id UUID := COALESCE(p_tenant_id, public.current_tenant_id());
BEGIN
  SELECT COALESCE(SUM(amount), 0) + p_amount INTO v_balance_after
  FROM public.customer_payment_ledger
  WHERE customer_id = p_customer_id
    AND (v_tenant_id IS NULL OR tenant_id = v_tenant_id);

  INSERT INTO public.customer_payment_ledger
    (customer_id, reference_type, reference_id, amount, balance_after, reason, created_by, created_at, tenant_id)
  VALUES (p_customer_id, p_reference_type, p_reference_id, p_amount, v_balance_after, p_reason, p_created_by, p_created_at, v_tenant_id);

  RETURN v_balance_after;
END;
$$;

-- ============================================================================
-- 4. Cập nhật process_checkout_tenant truyền tenant_id xuống ledger helpers
-- ============================================================================

CREATE OR REPLACE FUNCTION public.process_checkout_tenant(
  p_tenant_id UUID,
  p_order JSONB,
  p_items JSONB DEFAULT '[]'::JSONB,
  p_deltas JSONB DEFAULT '[]'::JSONB,
  p_reward_deltas JSONB DEFAULT '[]'::JSONB,
  p_customer_update JSONB DEFAULT NULL::JSONB,
  p_point_history JSONB DEFAULT '[]'::JSONB,
  p_allow_negative BOOLEAN DEFAULT FALSE,
  p_op_id TEXT DEFAULT NULL::TEXT
)
RETURNS JSONB
LANGUAGE plpgsql
SECURITY DEFINER
SET search_path = public
AS $$
DECLARE
  v_tenant          public.tenants%ROWTYPE;
  v_order_id        TEXT;
  v_customer_id     TEXT;
  v_item            JSONB;
  v_delta           JSONB;
  v_reward          JSONB;
  v_ph              JSONB;
  v_product         RECORD;
  v_reward_row      RECORD;
  v_lot             RECORD;
  v_lot_id          TEXT;
  v_deduct_qty      NUMERIC;
  v_new_qty         NUMERIC;
  v_new_stock       NUMERIC;
  v_add_spent       NUMERIC;
  v_add_debt        NUMERIC;
  v_add_points      NUMERIC;
  v_item_cost       NUMERIC;
  v_inserted_op     INTEGER;
  v_order_item_id   TEXT;
  v_idx             INTEGER;
  v_qty_after       NUMERIC;
  v_posting_date    TIMESTAMPTZ;
BEGIN
  IF p_tenant_id IS NULL THEN
    RAISE EXCEPTION 'tenant_id is required';
  END IF;

  SELECT * INTO v_tenant FROM public.tenants WHERE id = p_tenant_id;
  IF NOT FOUND OR v_tenant.status NOT IN ('active', 'trial') THEN
    RAISE EXCEPTION 'Tenant không hoạt động hoặc không tồn tại';
  END IF;

  v_order_id := p_order->>'id';
  IF v_order_id IS NULL OR v_order_id = '' THEN
    RAISE EXCEPTION 'order.id is required';
  END IF;

  v_posting_date := COALESCE((p_order->>'date')::TIMESTAMPTZ, NOW());

  IF p_op_id IS NOT NULL AND p_op_id != '' THEN
    INSERT INTO public.processed_operations (op_id, op_type, ref_id, tenant_id)
    VALUES (p_op_id, 'checkout', v_order_id, p_tenant_id)
    ON CONFLICT (op_id) DO NOTHING;
    GET DIAGNOSTICS v_inserted_op = ROW_COUNT;
    IF v_inserted_op = 0 THEN
      RETURN jsonb_build_object('ok', true, 'order_id', v_order_id, 'skipped', true, 'reason', 'op_id already processed');
    END IF;
  END IF;

  v_customer_id := p_order->>'customerId';
  IF v_customer_id IS NULL OR v_customer_id = '' OR v_customer_id = 'guest' THEN
    v_customer_id := NULL;
  END IF;

  IF v_customer_id IS NOT NULL THEN
    PERFORM 1 FROM public.customers WHERE id = v_customer_id AND tenant_id = p_tenant_id;
    IF NOT FOUND THEN
      RAISE EXCEPTION 'Khách hàng không thuộc tenant này';
    END IF;
  END IF;

  IF p_op_id IS NOT NULL AND p_op_id != '' THEN
    INSERT INTO public.orders (
      id, date, customer_id, customer_name,
      total_amount, paid_amount, debt_recorded, payment_method,
      status, points_earned, points_redeemed, rewards_redeemed,
      applied_promotions, note, tenant_id
    ) VALUES (
      v_order_id, v_posting_date, v_customer_id, p_order->>'customerName',
      COALESCE((p_order->>'totalAmount')::NUMERIC, 0),
      COALESCE((p_order->>'paidAmount')::NUMERIC, 0),
      COALESCE((p_order->>'debtRecorded')::NUMERIC, 0),
      p_order->>'paymentMethod',
      COALESCE(p_order->>'status', 'completed'),
      COALESCE((p_order->>'pointsEarned')::NUMERIC, 0),
      COALESCE((p_order->>'pointsRedeemed')::NUMERIC, 0),
      COALESCE(p_order->'rewardsRedeemed', '[]'::jsonb),
      COALESCE(p_order->'appliedPromotions', '[]'::jsonb),
      p_order->>'note',
      p_tenant_id
    );
  ELSE
    INSERT INTO public.orders (
      id, date, customer_id, customer_name,
      total_amount, paid_amount, debt_recorded, payment_method,
      status, points_earned, points_redeemed, rewards_redeemed,
      applied_promotions, note, tenant_id
    ) VALUES (
      v_order_id, v_posting_date, v_customer_id, p_order->>'customerName',
      COALESCE((p_order->>'totalAmount')::NUMERIC, 0),
      COALESCE((p_order->>'paidAmount')::NUMERIC, 0),
      COALESCE((p_order->>'debtRecorded')::NUMERIC, 0),
      p_order->>'paymentMethod',
      COALESCE(p_order->>'status', 'completed'),
      COALESCE((p_order->>'pointsEarned')::NUMERIC, 0),
      COALESCE((p_order->>'pointsRedeemed')::NUMERIC, 0),
      COALESCE(p_order->'rewardsRedeemed', '[]'::jsonb),
      COALESCE(p_order->'appliedPromotions', '[]'::jsonb),
      p_order->>'note',
      p_tenant_id
    )
    ON CONFLICT (id) DO UPDATE SET
      date               = EXCLUDED.date,
      customer_id        = EXCLUDED.customer_id,
      customer_name      = EXCLUDED.customer_name,
      total_amount       = EXCLUDED.total_amount,
      paid_amount        = EXCLUDED.paid_amount,
      debt_recorded      = EXCLUDED.debt_recorded,
      payment_method     = EXCLUDED.payment_method,
      status             = EXCLUDED.status,
      points_earned      = EXCLUDED.points_earned,
      points_redeemed    = EXCLUDED.points_redeemed,
      rewards_redeemed   = EXCLUDED.rewards_redeemed,
      applied_promotions = EXCLUDED.applied_promotions,
      note               = EXCLUDED.note,
      tenant_id          = EXCLUDED.tenant_id;
  END IF;

  CREATE TEMP TABLE IF NOT EXISTS tmp_phase7b_order_item_ids (
    idx INTEGER PRIMARY KEY,
    order_item_id TEXT
  ) ON COMMIT DROP;
  DELETE FROM tmp_phase7b_order_item_ids;

  DELETE FROM public.order_items WHERE order_id = v_order_id AND tenant_id = p_tenant_id;
  IF jsonb_typeof(p_items) = 'array' AND jsonb_array_length(p_items) > 0 THEN
    v_idx := 0;
    FOR v_item IN SELECT value FROM jsonb_array_elements(p_items) LOOP
      v_idx := v_idx + 1;
      v_item_cost := COALESCE(
        (v_item->>'cost')::NUMERIC,
        CASE
          WHEN NULLIF(v_item->>'lotId', '') IS NOT NULL THEN
            (SELECT cost FROM public.product_lots WHERE id = v_item->>'lotId' AND tenant_id = p_tenant_id)
          ELSE
            (SELECT cost FROM public.products WHERE id = v_item->>'productId' AND tenant_id = p_tenant_id)
        END,
        0
      );
      INSERT INTO public.order_items (
        order_id, product_id, product_name, quantity, unit_name, price,
        lot_id, lot_code, cost, tenant_id
      ) VALUES (
        v_order_id, v_item->>'productId', v_item->>'productName',
        COALESCE((v_item->>'quantity')::NUMERIC, 0), v_item->>'unitName',
        COALESCE((v_item->>'price')::NUMERIC, 0),
        NULLIF(v_item->>'lotId', ''), NULLIF(v_item->>'lotCode', ''),
        v_item_cost, p_tenant_id
      ) RETURNING id INTO v_order_item_id;
      INSERT INTO tmp_phase7b_order_item_ids (idx, order_item_id)
      VALUES (v_idx, v_order_item_id);
    END LOOP;
  END IF;

  IF jsonb_typeof(p_deltas) = 'array' AND jsonb_array_length(p_deltas) > 0 THEN
    FOR v_delta IN SELECT * FROM jsonb_array_elements(p_deltas) LOOP
      v_deduct_qty := COALESCE((v_delta->>'deductBaseQty')::NUMERIC, 0);
      v_lot_id     := NULLIF(v_delta->>'lotId', '');
      IF v_deduct_qty <= 0 THEN CONTINUE; END IF;
      SELECT id, name, quantity, has_lots INTO v_product
      FROM public.products WHERE id = v_delta->>'productId' AND tenant_id = p_tenant_id FOR UPDATE;
      IF NOT FOUND THEN
        RAISE EXCEPTION 'Sản phẩm % không tồn tại trong hệ thống', v_delta->>'productId';
      END IF;
      IF v_product.has_lots THEN
        IF v_lot_id IS NULL THEN
          RAISE EXCEPTION 'Sản phẩm "%" có quản lý lô, phải chọn lô khi bán', v_product.name
            USING ERRCODE = 'P0001';
        END IF;
        SELECT id, code, quantity INTO v_lot
        FROM public.product_lots WHERE id = v_lot_id AND product_id = v_product.id AND tenant_id = p_tenant_id FOR UPDATE;
        IF NOT FOUND THEN
          RAISE EXCEPTION 'Lô % không tồn tại cho sản phẩm "%"', v_lot_id, v_product.name;
        END IF;
        v_new_qty := COALESCE(v_lot.quantity, 0) - v_deduct_qty;
        IF v_new_qty < 0 AND NOT p_allow_negative THEN
          RAISE EXCEPTION 'Tồn lô "%" của "%" không đủ (còn %, cần %)',
            v_lot.code, v_product.name, v_lot.quantity, v_deduct_qty
            USING ERRCODE = 'P0001';
        END IF;
        UPDATE public.product_lots SET quantity = v_new_qty, updated_at = NOW() WHERE id = v_lot.id AND tenant_id = p_tenant_id;
      ELSE
        v_new_qty := COALESCE(v_product.quantity, 0) - v_deduct_qty;
        IF v_new_qty < 0 AND NOT p_allow_negative THEN
          RAISE EXCEPTION 'Tồn kho không đủ cho "%" (còn %, cần %)',
            v_product.name, v_product.quantity, v_deduct_qty
            USING ERRCODE = 'P0001';
        END IF;
        UPDATE public.products SET quantity = v_new_qty WHERE id = v_product.id AND tenant_id = p_tenant_id;
      END IF;
    END LOOP;
  END IF;

  IF jsonb_typeof(p_reward_deltas) = 'array' AND jsonb_array_length(p_reward_deltas) > 0 THEN
    FOR v_reward IN SELECT * FROM jsonb_array_elements(p_reward_deltas) LOOP
      IF COALESCE((v_reward->>'quantity')::NUMERIC, 0) <= 0 THEN CONTINUE; END IF;
      SELECT id, name, stock INTO v_reward_row
      FROM public.rewards WHERE id = v_reward->>'rewardId' AND tenant_id = p_tenant_id FOR UPDATE;
      IF NOT FOUND THEN CONTINUE; END IF;
      v_new_stock := COALESCE(v_reward_row.stock, 0) - (v_reward->>'quantity')::NUMERIC;
      IF v_new_stock < 0 AND NOT p_allow_negative THEN
        RAISE EXCEPTION 'Hết quà tặng "%" (còn %, cần %)',
          v_reward_row.name, v_reward_row.stock, v_reward->>'quantity';
      END IF;
      UPDATE public.rewards SET stock = GREATEST(v_new_stock, 0) WHERE id = v_reward_row.id AND tenant_id = p_tenant_id;
    END LOOP;
  END IF;

  IF jsonb_typeof(p_items) = 'array' AND jsonb_array_length(p_items) > 0 THEN
    v_idx := 0;
    FOR v_item IN SELECT value FROM jsonb_array_elements(p_items) LOOP
      v_idx := v_idx + 1;
      SELECT order_item_id INTO v_order_item_id FROM tmp_phase7b_order_item_ids WHERE idx = v_idx;
      IF v_order_item_id IS NULL THEN CONTINUE; END IF;
      v_lot_id := NULLIF(v_item->>'lotId', '');
      v_item_cost := COALESCE(
        (v_item->>'cost')::NUMERIC,
        CASE
          WHEN v_lot_id IS NOT NULL THEN (SELECT cost FROM public.product_lots WHERE id = v_lot_id AND tenant_id = p_tenant_id)
          ELSE (SELECT cost FROM public.products WHERE id = v_item->>'productId' AND tenant_id = p_tenant_id)
        END,
        0
      );
      v_qty_after := public.calc_qty_after_transaction(v_item->>'productId', v_lot_id, -COALESCE((v_item->>'quantity')::NUMERIC, 0), p_tenant_id);
      PERFORM public.insert_stock_ledger_entry(
        v_posting_date, 'Sales Invoice'::TEXT, v_order_id, v_order_item_id,
        v_item->>'productId', v_lot_id, 'Kho Chính'::TEXT,
        -COALESCE((v_item->>'quantity')::NUMERIC, 0), v_qty_after,
        v_item_cost, 0::NUMERIC, v_item_cost, NULL, FALSE,
        p_tenant_id
      );
    END LOOP;
  END IF;

  IF p_customer_update IS NOT NULL
     AND p_customer_update->>'customerId' IS NOT NULL
     AND p_customer_update->>'customerId' != ''
     AND p_customer_update->>'customerId' != 'guest' THEN
    v_add_spent  := COALESCE((p_customer_update->>'addSpent')::NUMERIC, 0);
    v_add_debt   := COALESCE((p_customer_update->>'addDebt')::NUMERIC, 0);
    v_add_points := COALESCE((p_customer_update->>'addPoints')::NUMERIC, 0);
    UPDATE public.customers SET
      total_spent        = GREATEST(0, COALESCE(total_spent, 0) + v_add_spent),
      debt               = GREATEST(0, COALESCE(debt, 0) + v_add_debt),
      loyalty_points     = GREATEST(0, COALESCE(loyalty_points, 0) + v_add_points),
      last_purchase_date = COALESCE(v_posting_date, NOW()),
      updated_at         = NOW()
    WHERE id = p_customer_update->>'customerId' AND tenant_id = p_tenant_id;

    IF v_add_debt > 0 THEN
      PERFORM public.insert_customer_ledger_entry(
        p_customer_id    := p_customer_update->>'customerId',
        p_reference_type := 'order',
        p_reference_id   := v_order_id,
        p_amount         := v_add_debt,
        p_reason         := 'Tạo đơn nợ ' || v_order_id,
        p_created_by     := COALESCE(NULLIF(p_op_id, ''), 'system'),
        p_created_at     := COALESCE(v_posting_date, NOW()),
        p_tenant_id      := p_tenant_id
      );
    END IF;
  END IF;

  IF jsonb_typeof(p_point_history) = 'array' AND jsonb_array_length(p_point_history) > 0 THEN
    FOR v_ph IN SELECT * FROM jsonb_array_elements(p_point_history) LOOP
      INSERT INTO public.point_history (id, customer_id, date, type, amount, description, order_id, tenant_id)
      VALUES (
        v_ph->>'id', NULLIF(v_ph->>'customerId', ''),
        COALESCE((v_ph->>'date')::TIMESTAMPTZ, NOW()), v_ph->>'type',
        COALESCE((v_ph->>'amount')::NUMERIC, 0), v_ph->>'description',
        NULLIF(v_ph->>'orderId', ''), p_tenant_id
      )
      ON CONFLICT (id) DO UPDATE SET
        amount      = EXCLUDED.amount,
        description = EXCLUDED.description;
    END LOOP;
  END IF;

  RETURN jsonb_build_object('ok', true, 'order_id', v_order_id, 'skipped', false);
END;
$$;

-- === MIGRATION END: 20250705000005_phase9_5_process_checkout_ledger_fixes.sql ===

-- === MIGRATION START: 20250705000006_phase9_5_safeupdate_fix.sql ===
-- SOURCE_PATH: C:\Users\SUACAUBA\Downloads\Project\vietsale-pro-v7\supabase\migrations\20250705000006_phase9_5_safeupdate_fix.sql
-- SIZE_BYTES: 26523
-- SHA256: 840792A9E9791DE481F87FF6B63ADF4198389114A8E2A7217F341C2D402D35CE

-- Sub-phase 9.5 follow-up: safeupdate extension yêu cầu DELETE có WHERE clause.
-- Cả process_checkout và process_checkout_tenant đều dùng temp table và DELETE không WHERE.
-- ponytail: Thay WHERE TRUE thay vì xóa temp table logic (function cần reset dữ liệu temp giữa các lần gọi trong transaction).

CREATE OR REPLACE FUNCTION public.process_checkout(
  p_order JSONB,
  p_items JSONB DEFAULT '[]'::JSONB,
  p_deltas JSONB DEFAULT '[]'::JSONB,
  p_reward_deltas JSONB DEFAULT '[]'::JSONB,
  p_customer_update JSONB DEFAULT NULL::JSONB,
  p_point_history JSONB DEFAULT '[]'::JSONB,
  p_allow_negative BOOLEAN DEFAULT FALSE,
  p_op_id TEXT DEFAULT NULL::TEXT
)
RETURNS JSONB
LANGUAGE plpgsql
SECURITY DEFINER
SET search_path = public
AS $$
DECLARE
  v_order_id        TEXT;
  v_customer_id     TEXT;
  v_item            JSONB;
  v_delta           JSONB;
  v_reward          JSONB;
  v_ph              JSONB;
  v_product         RECORD;
  v_reward_row      RECORD;
  v_lot             RECORD;
  v_lot_id          TEXT;
  v_deduct_qty      NUMERIC;
  v_new_qty         NUMERIC;
  v_new_stock       NUMERIC;
  v_add_spent       NUMERIC;
  v_add_debt        NUMERIC;
  v_add_points      NUMERIC;
  v_item_cost       NUMERIC;
  v_inserted_op     INTEGER;
  v_order_item_id   TEXT;
  v_idx             INTEGER;
  v_qty_after       NUMERIC;
  v_posting_date    TIMESTAMPTZ;
BEGIN
  v_order_id := p_order->>'id';
  IF v_order_id IS NULL OR v_order_id = '' THEN
    RAISE EXCEPTION 'order.id is required';
  END IF;

  v_posting_date := COALESCE((p_order->>'date')::TIMESTAMPTZ, NOW());

  IF p_op_id IS NOT NULL AND p_op_id != '' THEN
    INSERT INTO public.processed_operations (op_id, op_type, ref_id, tenant_id)
    VALUES (p_op_id, 'checkout', v_order_id, public.current_tenant_id())
    ON CONFLICT (op_id) DO NOTHING;
    GET DIAGNOSTICS v_inserted_op = ROW_COUNT;
    IF v_inserted_op = 0 THEN
      RETURN jsonb_build_object('ok', true, 'order_id', v_order_id, 'skipped', true, 'reason', 'op_id already processed');
    END IF;
  END IF;

  v_customer_id := p_order->>'customerId';
  IF v_customer_id IS NULL OR v_customer_id = '' OR v_customer_id = 'guest' THEN
    v_customer_id := NULL;
  END IF;

  IF p_op_id IS NOT NULL AND p_op_id != '' THEN
    INSERT INTO public.orders (
      id, date, customer_id, customer_name,
      total_amount, paid_amount, debt_recorded, payment_method,
      status, points_earned, points_redeemed, rewards_redeemed,
      applied_promotions, note, tenant_id
    ) VALUES (
      v_order_id, v_posting_date, v_customer_id, p_order->>'customerName',
      COALESCE((p_order->>'totalAmount')::NUMERIC, 0),
      COALESCE((p_order->>'paidAmount')::NUMERIC, 0),
      COALESCE((p_order->>'debtRecorded')::NUMERIC, 0),
      p_order->>'paymentMethod',
      COALESCE(p_order->>'status', 'completed'),
      COALESCE((p_order->>'pointsEarned')::NUMERIC, 0),
      COALESCE((p_order->>'pointsRedeemed')::NUMERIC, 0),
      COALESCE(p_order->'rewardsRedeemed', '[]'::jsonb),
      COALESCE(p_order->'appliedPromotions', '[]'::jsonb),
      p_order->>'note',
      public.current_tenant_id()
    );
  ELSE
    INSERT INTO public.orders (
      id, date, customer_id, customer_name,
      total_amount, paid_amount, debt_recorded, payment_method,
      status, points_earned, points_redeemed, rewards_redeemed,
      applied_promotions, note, tenant_id
    ) VALUES (
      v_order_id, v_posting_date, v_customer_id, p_order->>'customerName',
      COALESCE((p_order->>'totalAmount')::NUMERIC, 0),
      COALESCE((p_order->>'paidAmount')::NUMERIC, 0),
      COALESCE((p_order->>'debtRecorded')::NUMERIC, 0),
      p_order->>'paymentMethod',
      COALESCE(p_order->>'status', 'completed'),
      COALESCE((p_order->>'pointsEarned')::NUMERIC, 0),
      COALESCE((p_order->>'pointsRedeemed')::NUMERIC, 0),
      COALESCE(p_order->'rewardsRedeemed', '[]'::jsonb),
      COALESCE(p_order->'appliedPromotions', '[]'::jsonb),
      p_order->>'note',
      public.current_tenant_id()
    )
    ON CONFLICT (id) DO UPDATE SET
      date               = EXCLUDED.date,
      customer_id        = EXCLUDED.customer_id,
      customer_name      = EXCLUDED.customer_name,
      total_amount       = EXCLUDED.total_amount,
      paid_amount        = EXCLUDED.paid_amount,
      debt_recorded      = EXCLUDED.debt_recorded,
      payment_method     = EXCLUDED.payment_method,
      status             = EXCLUDED.status,
      points_earned      = EXCLUDED.points_earned,
      points_redeemed    = EXCLUDED.points_redeemed,
      rewards_redeemed   = EXCLUDED.rewards_redeemed,
      applied_promotions = EXCLUDED.applied_promotions,
      note               = EXCLUDED.note,
      tenant_id          = EXCLUDED.tenant_id;
  END IF;

  CREATE TEMP TABLE IF NOT EXISTS tmp_phase7b_order_item_ids (
    idx INTEGER PRIMARY KEY,
    order_item_id TEXT
  ) ON COMMIT DROP;
  DELETE FROM tmp_phase7b_order_item_ids WHERE TRUE;

  DELETE FROM public.order_items WHERE order_id = v_order_id AND tenant_id = public.current_tenant_id();
  IF jsonb_typeof(p_items) = 'array' AND jsonb_array_length(p_items) > 0 THEN
    v_idx := 0;
    FOR v_item IN SELECT value FROM jsonb_array_elements(p_items) LOOP
      v_idx := v_idx + 1;
      v_item_cost := COALESCE(
        (v_item->>'cost')::NUMERIC,
        CASE
          WHEN NULLIF(v_item->>'lotId', '') IS NOT NULL THEN
            (SELECT cost FROM public.product_lots WHERE id = v_item->>'lotId' AND tenant_id = public.current_tenant_id())
          ELSE
            (SELECT cost FROM public.products WHERE id = v_item->>'productId' AND tenant_id = public.current_tenant_id())
        END,
        0
      );
      INSERT INTO public.order_items (
        order_id, product_id, product_name, quantity, unit_name, price,
        lot_id, lot_code, cost, tenant_id
      ) VALUES (
        v_order_id, v_item->>'productId', v_item->>'productName',
        COALESCE((v_item->>'quantity')::NUMERIC, 0), v_item->>'unitName',
        COALESCE((v_item->>'price')::NUMERIC, 0),
        NULLIF(v_item->>'lotId', ''), NULLIF(v_item->>'lotCode', ''),
        v_item_cost, public.current_tenant_id()
      ) RETURNING id INTO v_order_item_id;
      INSERT INTO tmp_phase7b_order_item_ids (idx, order_item_id)
      VALUES (v_idx, v_order_item_id);
    END LOOP;
  END IF;

  IF jsonb_typeof(p_deltas) = 'array' AND jsonb_array_length(p_deltas) > 0 THEN
    FOR v_delta IN SELECT * FROM jsonb_array_elements(p_deltas) LOOP
      v_deduct_qty := COALESCE((v_delta->>'deductBaseQty')::NUMERIC, 0);
      v_lot_id     := NULLIF(v_delta->>'lotId', '');
      IF v_deduct_qty <= 0 THEN CONTINUE; END IF;
      SELECT id, name, quantity, has_lots INTO v_product
      FROM public.products WHERE id = v_delta->>'productId' AND tenant_id = public.current_tenant_id() FOR UPDATE;
      IF NOT FOUND THEN
        RAISE EXCEPTION 'Sản phẩm % không tồn tại trong hệ thống', v_delta->>'productId';
      END IF;
      IF v_product.has_lots THEN
        IF v_lot_id IS NULL THEN
          RAISE EXCEPTION 'Sản phẩm "%" có quản lý lô, phải chọn lô khi bán', v_product.name
            USING ERRCODE = 'P0001';
        END IF;
        SELECT id, code, quantity INTO v_lot
        FROM public.product_lots WHERE id = v_lot_id AND product_id = v_product.id AND tenant_id = public.current_tenant_id() FOR UPDATE;
        IF NOT FOUND THEN
          RAISE EXCEPTION 'Lô % không tồn tại cho sản phẩm "%"', v_lot_id, v_product.name;
        END IF;
        v_new_qty := COALESCE(v_lot.quantity, 0) - v_deduct_qty;
        IF v_new_qty < 0 AND NOT p_allow_negative THEN
          RAISE EXCEPTION 'Tồn lô "%" của "%" không đủ (còn %, cần %)',
            v_lot.code, v_product.name, v_lot.quantity, v_deduct_qty
            USING ERRCODE = 'P0001';
        END IF;
        UPDATE public.product_lots SET quantity = v_new_qty, updated_at = NOW() WHERE id = v_lot.id AND tenant_id = public.current_tenant_id();
      ELSE
        v_new_qty := COALESCE(v_product.quantity, 0) - v_deduct_qty;
        IF v_new_qty < 0 AND NOT p_allow_negative THEN
          RAISE EXCEPTION 'Tồn kho không đủ cho "%" (còn %, cần %)',
            v_product.name, v_product.quantity, v_deduct_qty
            USING ERRCODE = 'P0001';
        END IF;
        UPDATE public.products SET quantity = v_new_qty WHERE id = v_product.id AND tenant_id = public.current_tenant_id();
      END IF;
    END LOOP;
  END IF;

  IF jsonb_typeof(p_reward_deltas) = 'array' AND jsonb_array_length(p_reward_deltas) > 0 THEN
    FOR v_reward IN SELECT * FROM jsonb_array_elements(p_reward_deltas) LOOP
      IF COALESCE((v_reward->>'quantity')::NUMERIC, 0) <= 0 THEN CONTINUE; END IF;
      SELECT id, name, stock INTO v_reward_row
      FROM public.rewards WHERE id = v_reward->>'rewardId' AND tenant_id = public.current_tenant_id() FOR UPDATE;
      IF NOT FOUND THEN CONTINUE; END IF;
      v_new_stock := COALESCE(v_reward_row.stock, 0) - (v_reward->>'quantity')::NUMERIC;
      IF v_new_stock < 0 AND NOT p_allow_negative THEN
        RAISE EXCEPTION 'Hết quà tặng "%" (còn %, cần %)',
          v_reward_row.name, v_reward_row.stock, v_reward->>'quantity';
      END IF;
      UPDATE public.rewards SET stock = GREATEST(v_new_stock, 0) WHERE id = v_reward_row.id AND tenant_id = public.current_tenant_id();
    END LOOP;
  END IF;

  IF jsonb_typeof(p_items) = 'array' AND jsonb_array_length(p_items) > 0 THEN
    v_idx := 0;
    FOR v_item IN SELECT value FROM jsonb_array_elements(p_items) LOOP
      v_idx := v_idx + 1;
      SELECT order_item_id INTO v_order_item_id FROM tmp_phase7b_order_item_ids WHERE idx = v_idx;
      IF v_order_item_id IS NULL THEN CONTINUE; END IF;
      v_lot_id := NULLIF(v_item->>'lotId', '');
      v_item_cost := COALESCE(
        (v_item->>'cost')::NUMERIC,
        CASE
          WHEN v_lot_id IS NOT NULL THEN (SELECT cost FROM public.product_lots WHERE id = v_lot_id AND tenant_id = public.current_tenant_id())
          ELSE (SELECT cost FROM public.products WHERE id = v_item->>'productId' AND tenant_id = public.current_tenant_id())
        END,
        0
      );
      v_qty_after := public.calc_qty_after_transaction(v_item->>'productId', v_lot_id, -COALESCE((v_item->>'quantity')::NUMERIC, 0), public.current_tenant_id());
      PERFORM public.insert_stock_ledger_entry(
        v_posting_date, 'Sales Invoice'::TEXT, v_order_id, v_order_item_id,
        v_item->>'productId', v_lot_id, 'Kho Chính'::TEXT,
        -COALESCE((v_item->>'quantity')::NUMERIC, 0), v_qty_after,
        v_item_cost, 0::NUMERIC, v_item_cost, NULL, FALSE,
        public.current_tenant_id()
      );
    END LOOP;
  END IF;

  IF p_customer_update IS NOT NULL
     AND p_customer_update->>'customerId' IS NOT NULL
     AND p_customer_update->>'customerId' != ''
     AND p_customer_update->>'customerId' != 'guest' THEN
    v_add_spent  := COALESCE((p_customer_update->>'addSpent')::NUMERIC, 0);
    v_add_debt   := COALESCE((p_customer_update->>'addDebt')::NUMERIC, 0);
    v_add_points := COALESCE((p_customer_update->>'addPoints')::NUMERIC, 0);
    UPDATE public.customers SET
      total_spent        = GREATEST(0, COALESCE(total_spent, 0) + v_add_spent),
      debt               = GREATEST(0, COALESCE(debt, 0) + v_add_debt),
      loyalty_points     = GREATEST(0, COALESCE(loyalty_points, 0) + v_add_points),
      last_purchase_date = COALESCE(v_posting_date, NOW()),
      updated_at         = NOW()
    WHERE id = p_customer_update->>'customerId' AND tenant_id = public.current_tenant_id();

    IF v_add_debt > 0 THEN
      PERFORM public.insert_customer_ledger_entry(
        p_customer_id    := p_customer_update->>'customerId',
        p_reference_type := 'order',
        p_reference_id   := v_order_id,
        p_amount         := v_add_debt,
        p_reason         := 'Tạo đơn nợ ' || v_order_id,
        p_created_by     := COALESCE(NULLIF(p_op_id, ''), 'system'),
        p_created_at     := COALESCE(v_posting_date, NOW()),
        p_tenant_id      := public.current_tenant_id()
      );
    END IF;
  END IF;

  IF jsonb_typeof(p_point_history) = 'array' AND jsonb_array_length(p_point_history) > 0 THEN
    FOR v_ph IN SELECT * FROM jsonb_array_elements(p_point_history) LOOP
      INSERT INTO public.point_history (id, customer_id, date, type, amount, description, order_id, tenant_id)
      VALUES (
        v_ph->>'id', NULLIF(v_ph->>'customerId', ''),
        COALESCE((v_ph->>'date')::TIMESTAMPTZ, NOW()), v_ph->>'type',
        COALESCE((v_ph->>'amount')::NUMERIC, 0), v_ph->>'description',
        NULLIF(v_ph->>'orderId', ''), public.current_tenant_id()
      )
      ON CONFLICT (id) DO UPDATE SET
        amount      = EXCLUDED.amount,
        description = EXCLUDED.description;
    END LOOP;
  END IF;

  RETURN jsonb_build_object('ok', true, 'order_id', v_order_id, 'skipped', false);
END;
$$;

-- Cập nhật process_checkout_tenant (chỉ thay đổi DELETE WHERE TRUE)
CREATE OR REPLACE FUNCTION public.process_checkout_tenant(
  p_tenant_id UUID,
  p_order JSONB,
  p_items JSONB DEFAULT '[]'::JSONB,
  p_deltas JSONB DEFAULT '[]'::JSONB,
  p_reward_deltas JSONB DEFAULT '[]'::JSONB,
  p_customer_update JSONB DEFAULT NULL::JSONB,
  p_point_history JSONB DEFAULT '[]'::JSONB,
  p_allow_negative BOOLEAN DEFAULT FALSE,
  p_op_id TEXT DEFAULT NULL::TEXT
)
RETURNS JSONB
LANGUAGE plpgsql
SECURITY DEFINER
SET search_path = public
AS $$
DECLARE
  v_tenant          public.tenants%ROWTYPE;
  v_order_id        TEXT;
  v_customer_id     TEXT;
  v_item            JSONB;
  v_delta           JSONB;
  v_reward          JSONB;
  v_ph              JSONB;
  v_product         RECORD;
  v_reward_row      RECORD;
  v_lot             RECORD;
  v_lot_id          TEXT;
  v_deduct_qty      NUMERIC;
  v_new_qty         NUMERIC;
  v_new_stock       NUMERIC;
  v_add_spent       NUMERIC;
  v_add_debt        NUMERIC;
  v_add_points      NUMERIC;
  v_item_cost       NUMERIC;
  v_inserted_op     INTEGER;
  v_order_item_id   TEXT;
  v_idx             INTEGER;
  v_qty_after       NUMERIC;
  v_posting_date    TIMESTAMPTZ;
BEGIN
  IF p_tenant_id IS NULL THEN
    RAISE EXCEPTION 'tenant_id is required';
  END IF;

  SELECT * INTO v_tenant FROM public.tenants WHERE id = p_tenant_id;
  IF NOT FOUND OR v_tenant.status NOT IN ('active', 'trial') THEN
    RAISE EXCEPTION 'Tenant không hoạt động hoặc không tồn tại';
  END IF;

  v_order_id := p_order->>'id';
  IF v_order_id IS NULL OR v_order_id = '' THEN
    RAISE EXCEPTION 'order.id is required';
  END IF;

  v_posting_date := COALESCE((p_order->>'date')::TIMESTAMPTZ, NOW());

  IF p_op_id IS NOT NULL AND p_op_id != '' THEN
    INSERT INTO public.processed_operations (op_id, op_type, ref_id, tenant_id)
    VALUES (p_op_id, 'checkout', v_order_id, p_tenant_id)
    ON CONFLICT (op_id) DO NOTHING;
    GET DIAGNOSTICS v_inserted_op = ROW_COUNT;
    IF v_inserted_op = 0 THEN
      RETURN jsonb_build_object('ok', true, 'order_id', v_order_id, 'skipped', true, 'reason', 'op_id already processed');
    END IF;
  END IF;

  v_customer_id := p_order->>'customerId';
  IF v_customer_id IS NULL OR v_customer_id = '' OR v_customer_id = 'guest' THEN
    v_customer_id := NULL;
  END IF;

  IF v_customer_id IS NOT NULL THEN
    PERFORM 1 FROM public.customers WHERE id = v_customer_id AND tenant_id = p_tenant_id;
    IF NOT FOUND THEN
      RAISE EXCEPTION 'Khách hàng không thuộc tenant này';
    END IF;
  END IF;

  IF p_op_id IS NOT NULL AND p_op_id != '' THEN
    INSERT INTO public.orders (
      id, date, customer_id, customer_name,
      total_amount, paid_amount, debt_recorded, payment_method,
      status, points_earned, points_redeemed, rewards_redeemed,
      applied_promotions, note, tenant_id
    ) VALUES (
      v_order_id, v_posting_date, v_customer_id, p_order->>'customerName',
      COALESCE((p_order->>'totalAmount')::NUMERIC, 0),
      COALESCE((p_order->>'paidAmount')::NUMERIC, 0),
      COALESCE((p_order->>'debtRecorded')::NUMERIC, 0),
      p_order->>'paymentMethod',
      COALESCE(p_order->>'status', 'completed'),
      COALESCE((p_order->>'pointsEarned')::NUMERIC, 0),
      COALESCE((p_order->>'pointsRedeemed')::NUMERIC, 0),
      COALESCE(p_order->'rewardsRedeemed', '[]'::jsonb),
      COALESCE(p_order->'appliedPromotions', '[]'::jsonb),
      p_order->>'note',
      p_tenant_id
    );
  ELSE
    INSERT INTO public.orders (
      id, date, customer_id, customer_name,
      total_amount, paid_amount, debt_recorded, payment_method,
      status, points_earned, points_redeemed, rewards_redeemed,
      applied_promotions, note, tenant_id
    ) VALUES (
      v_order_id, v_posting_date, v_customer_id, p_order->>'customerName',
      COALESCE((p_order->>'totalAmount')::NUMERIC, 0),
      COALESCE((p_order->>'paidAmount')::NUMERIC, 0),
      COALESCE((p_order->>'debtRecorded')::NUMERIC, 0),
      p_order->>'paymentMethod',
      COALESCE(p_order->>'status', 'completed'),
      COALESCE((p_order->>'pointsEarned')::NUMERIC, 0),
      COALESCE((p_order->>'pointsRedeemed')::NUMERIC, 0),
      COALESCE(p_order->'rewardsRedeemed', '[]'::jsonb),
      COALESCE(p_order->'appliedPromotions', '[]'::jsonb),
      p_order->>'note',
      p_tenant_id
    )
    ON CONFLICT (id) DO UPDATE SET
      date               = EXCLUDED.date,
      customer_id        = EXCLUDED.customer_id,
      customer_name      = EXCLUDED.customer_name,
      total_amount       = EXCLUDED.total_amount,
      paid_amount        = EXCLUDED.paid_amount,
      debt_recorded      = EXCLUDED.debt_recorded,
      payment_method     = EXCLUDED.payment_method,
      status             = EXCLUDED.status,
      points_earned      = EXCLUDED.points_earned,
      points_redeemed    = EXCLUDED.points_redeemed,
      rewards_redeemed   = EXCLUDED.rewards_redeemed,
      applied_promotions = EXCLUDED.applied_promotions,
      note               = EXCLUDED.note,
      tenant_id          = EXCLUDED.tenant_id;
  END IF;

  CREATE TEMP TABLE IF NOT EXISTS tmp_phase7b_order_item_ids (
    idx INTEGER PRIMARY KEY,
    order_item_id TEXT
  ) ON COMMIT DROP;
  DELETE FROM tmp_phase7b_order_item_ids WHERE TRUE;

  DELETE FROM public.order_items WHERE order_id = v_order_id AND tenant_id = p_tenant_id;
  IF jsonb_typeof(p_items) = 'array' AND jsonb_array_length(p_items) > 0 THEN
    v_idx := 0;
    FOR v_item IN SELECT value FROM jsonb_array_elements(p_items) LOOP
      v_idx := v_idx + 1;
      v_item_cost := COALESCE(
        (v_item->>'cost')::NUMERIC,
        CASE
          WHEN NULLIF(v_item->>'lotId', '') IS NOT NULL THEN
            (SELECT cost FROM public.product_lots WHERE id = v_item->>'lotId' AND tenant_id = p_tenant_id)
          ELSE
            (SELECT cost FROM public.products WHERE id = v_item->>'productId' AND tenant_id = p_tenant_id)
        END,
        0
      );
      INSERT INTO public.order_items (
        order_id, product_id, product_name, quantity, unit_name, price,
        lot_id, lot_code, cost, tenant_id
      ) VALUES (
        v_order_id, v_item->>'productId', v_item->>'productName',
        COALESCE((v_item->>'quantity')::NUMERIC, 0), v_item->>'unitName',
        COALESCE((v_item->>'price')::NUMERIC, 0),
        NULLIF(v_item->>'lotId', ''), NULLIF(v_item->>'lotCode', ''),
        v_item_cost, p_tenant_id
      ) RETURNING id INTO v_order_item_id;
      INSERT INTO tmp_phase7b_order_item_ids (idx, order_item_id)
      VALUES (v_idx, v_order_item_id);
    END LOOP;
  END IF;

  IF jsonb_typeof(p_deltas) = 'array' AND jsonb_array_length(p_deltas) > 0 THEN
    FOR v_delta IN SELECT * FROM jsonb_array_elements(p_deltas) LOOP
      v_deduct_qty := COALESCE((v_delta->>'deductBaseQty')::NUMERIC, 0);
      v_lot_id     := NULLIF(v_delta->>'lotId', '');
      IF v_deduct_qty <= 0 THEN CONTINUE; END IF;
      SELECT id, name, quantity, has_lots INTO v_product
      FROM public.products WHERE id = v_delta->>'productId' AND tenant_id = p_tenant_id FOR UPDATE;
      IF NOT FOUND THEN
        RAISE EXCEPTION 'Sản phẩm % không tồn tại trong hệ thống', v_delta->>'productId';
      END IF;
      IF v_product.has_lots THEN
        IF v_lot_id IS NULL THEN
          RAISE EXCEPTION 'Sản phẩm "%" có quản lý lô, phải chọn lô khi bán', v_product.name
            USING ERRCODE = 'P0001';
        END IF;
        SELECT id, code, quantity INTO v_lot
        FROM public.product_lots WHERE id = v_lot_id AND product_id = v_product.id AND tenant_id = p_tenant_id FOR UPDATE;
        IF NOT FOUND THEN
          RAISE EXCEPTION 'Lô % không tồn tại cho sản phẩm "%"', v_lot_id, v_product.name;
        END IF;
        v_new_qty := COALESCE(v_lot.quantity, 0) - v_deduct_qty;
        IF v_new_qty < 0 AND NOT p_allow_negative THEN
          RAISE EXCEPTION 'Tồn lô "%" của "%" không đủ (còn %, cần %)',
            v_lot.code, v_product.name, v_lot.quantity, v_deduct_qty
            USING ERRCODE = 'P0001';
        END IF;
        UPDATE public.product_lots SET quantity = v_new_qty, updated_at = NOW() WHERE id = v_lot.id AND tenant_id = p_tenant_id;
      ELSE
        v_new_qty := COALESCE(v_product.quantity, 0) - v_deduct_qty;
        IF v_new_qty < 0 AND NOT p_allow_negative THEN
          RAISE EXCEPTION 'Tồn kho không đủ cho "%" (còn %, cần %)',
            v_product.name, v_product.quantity, v_deduct_qty
            USING ERRCODE = 'P0001';
        END IF;
        UPDATE public.products SET quantity = v_new_qty WHERE id = v_product.id AND tenant_id = p_tenant_id;
      END IF;
    END LOOP;
  END IF;

  IF jsonb_typeof(p_reward_deltas) = 'array' AND jsonb_array_length(p_reward_deltas) > 0 THEN
    FOR v_reward IN SELECT * FROM jsonb_array_elements(p_reward_deltas) LOOP
      IF COALESCE((v_reward->>'quantity')::NUMERIC, 0) <= 0 THEN CONTINUE; END IF;
      SELECT id, name, stock INTO v_reward_row
      FROM public.rewards WHERE id = v_reward->>'rewardId' AND tenant_id = p_tenant_id FOR UPDATE;
      IF NOT FOUND THEN CONTINUE; END IF;
      v_new_stock := COALESCE(v_reward_row.stock, 0) - (v_reward->>'quantity')::NUMERIC;
      IF v_new_stock < 0 AND NOT p_allow_negative THEN
        RAISE EXCEPTION 'Hết quà tặng "%" (còn %, cần %)',
          v_reward_row.name, v_reward_row.stock, v_reward->>'quantity';
      END IF;
      UPDATE public.rewards SET stock = GREATEST(v_new_stock, 0) WHERE id = v_reward_row.id AND tenant_id = p_tenant_id;
    END LOOP;
  END IF;

  IF jsonb_typeof(p_items) = 'array' AND jsonb_array_length(p_items) > 0 THEN
    v_idx := 0;
    FOR v_item IN SELECT value FROM jsonb_array_elements(p_items) LOOP
      v_idx := v_idx + 1;
      SELECT order_item_id INTO v_order_item_id FROM tmp_phase7b_order_item_ids WHERE idx = v_idx;
      IF v_order_item_id IS NULL THEN CONTINUE; END IF;
      v_lot_id := NULLIF(v_item->>'lotId', '');
      v_item_cost := COALESCE(
        (v_item->>'cost')::NUMERIC,
        CASE
          WHEN v_lot_id IS NOT NULL THEN (SELECT cost FROM public.product_lots WHERE id = v_lot_id AND tenant_id = p_tenant_id)
          ELSE (SELECT cost FROM public.products WHERE id = v_item->>'productId' AND tenant_id = p_tenant_id)
        END,
        0
      );
      v_qty_after := public.calc_qty_after_transaction(v_item->>'productId', v_lot_id, -COALESCE((v_item->>'quantity')::NUMERIC, 0), p_tenant_id);
      PERFORM public.insert_stock_ledger_entry(
        v_posting_date, 'Sales Invoice'::TEXT, v_order_id, v_order_item_id,
        v_item->>'productId', v_lot_id, 'Kho Chính'::TEXT,
        -COALESCE((v_item->>'quantity')::NUMERIC, 0), v_qty_after,
        v_item_cost, 0::NUMERIC, v_item_cost, NULL, FALSE,
        p_tenant_id
      );
    END LOOP;
  END IF;

  IF p_customer_update IS NOT NULL
     AND p_customer_update->>'customerId' IS NOT NULL
     AND p_customer_update->>'customerId' != ''
     AND p_customer_update->>'customerId' != 'guest' THEN
    v_add_spent  := COALESCE((p_customer_update->>'addSpent')::NUMERIC, 0);
    v_add_debt   := COALESCE((p_customer_update->>'addDebt')::NUMERIC, 0);
    v_add_points := COALESCE((p_customer_update->>'addPoints')::NUMERIC, 0);
    UPDATE public.customers SET
      total_spent        = GREATEST(0, COALESCE(total_spent, 0) + v_add_spent),
      debt               = GREATEST(0, COALESCE(debt, 0) + v_add_debt),
      loyalty_points     = GREATEST(0, COALESCE(loyalty_points, 0) + v_add_points),
      last_purchase_date = COALESCE(v_posting_date, NOW()),
      updated_at         = NOW()
    WHERE id = p_customer_update->>'customerId' AND tenant_id = p_tenant_id;

    IF v_add_debt > 0 THEN
      PERFORM public.insert_customer_ledger_entry(
        p_customer_id    := p_customer_update->>'customerId',
        p_reference_type := 'order',
        p_reference_id   := v_order_id,
        p_amount         := v_add_debt,
        p_reason         := 'Tạo đơn nợ ' || v_order_id,
        p_created_by     := COALESCE(NULLIF(p_op_id, ''), 'system'),
        p_created_at     := COALESCE(v_posting_date, NOW()),
        p_tenant_id      := p_tenant_id
      );
    END IF;
  END IF;

  IF jsonb_typeof(p_point_history) = 'array' AND jsonb_array_length(p_point_history) > 0 THEN
    FOR v_ph IN SELECT * FROM jsonb_array_elements(p_point_history) LOOP
      INSERT INTO public.point_history (id, customer_id, date, type, amount, description, order_id, tenant_id)
      VALUES (
        v_ph->>'id', NULLIF(v_ph->>'customerId', ''),
        COALESCE((v_ph->>'date')::TIMESTAMPTZ, NOW()), v_ph->>'type',
        COALESCE((v_ph->>'amount')::NUMERIC, 0), v_ph->>'description',
        NULLIF(v_ph->>'orderId', ''), p_tenant_id
      )
      ON CONFLICT (id) DO UPDATE SET
        amount      = EXCLUDED.amount,
        description = EXCLUDED.description;
    END LOOP;
  END IF;

  RETURN jsonb_build_object('ok', true, 'order_id', v_order_id, 'skipped', false);
END;
$$;

-- === MIGRATION END: 20250705000006_phase9_5_safeupdate_fix.sql ===

