-- === MIGRATION START: 20250706000009_phase_p7_3_payment_confirm_lifecycle.sql ===
-- SOURCE_PATH: C:\Users\SUACAUBA\Downloads\Project\vietsale-pro-v7\supabase\migrations\20250706000009_phase_p7_3_payment_confirm_lifecycle.sql
-- SIZE_BYTES: 4257
-- SHA256: F334EDEB66C4FFCC07AD18568008A2036E8C9CC671C62ED625B68244EA624614

-- P7.3: Xác nhận thanh toán + vòng đời trạng thái hóa đơn (pending/paid/overdue/cancelled/expired).
-- ponytail: migration idempotent; chỉ system admin được confirm; cho phép confirm trên hóa đơn expired để kích hoạt lại tenant.

-- ============================================================
-- 1. Bổ sung trạng thái 'expired' vào CHECK constraint invoices.status
-- ============================================================

DO $$
DECLARE
  rec RECORD;
BEGIN
  FOR rec IN
    SELECT con.conname
    FROM pg_constraint con
    JOIN pg_attribute att ON att.attrelid = con.conrelid AND att.attnum = ANY(con.conkey)
    WHERE con.conrelid = 'public.invoices'::regclass
      AND con.contype = 'c'
      AND att.attname = 'status'
  LOOP
    EXECUTE format('ALTER TABLE public.invoices DROP CONSTRAINT IF EXISTS %I', rec.conname);
  END LOOP;
END $$;

ALTER TABLE public.invoices
  ADD CONSTRAINT invoices_status_check
  CHECK (status IN ('draft', 'pending', 'paid', 'overdue', 'cancelled', 'expired'));

-- ============================================================
-- 2. RPC xác nhận thanh toán + ghi payment + kích hoạt lại tenant
-- ============================================================

CREATE OR REPLACE FUNCTION public.confirm_payment(
  p_invoice_id UUID,
  p_payment_method TEXT DEFAULT 'bank_transfer',
  p_reference_code TEXT DEFAULT NULL,
  p_notes TEXT DEFAULT NULL
)
RETURNS public.payments
LANGUAGE plpgsql
SECURITY INVOKER
SET search_path = public
SET timezone = 'Asia/Ho_Chi_Minh'
AS $$
DECLARE
  v_invoice public.invoices%ROWTYPE;
  v_tenant public.tenants%ROWTYPE;
  v_sub public.tenant_subscriptions%ROWTYPE;
  v_payment public.payments%ROWTYPE;
  v_new_expires_at TIMESTAMPTZ;
BEGIN
  IF NOT public.is_system_admin() THEN
    RAISE EXCEPTION 'Chỉ system admin mới được xác nhận thanh toán' USING ERRCODE = 'insufficient_privilege';
  END IF;

  IF p_payment_method NOT IN ('bank_transfer', 'cash', 'card', 'other') THEN
    RAISE EXCEPTION 'Phương thức thanh toán không hợp lệ: %', p_payment_method;
  END IF;

  SELECT * INTO v_invoice FROM public.invoices WHERE id = p_invoice_id;
  IF NOT FOUND THEN
    RAISE EXCEPTION 'Không tìm thấy hóa đơn: %', p_invoice_id;
  END IF;

  IF v_invoice.status IN ('paid', 'cancelled', 'draft') THEN
    RAISE EXCEPTION 'Hóa đơn ở trạng thái %, không thể xác nhận thanh toán', v_invoice.status;
  END IF;

  SELECT * INTO v_tenant FROM public.tenants WHERE id = v_invoice.tenant_id;
  IF NOT FOUND THEN
    RAISE EXCEPTION 'Không tìm thấy tenant: %', v_invoice.tenant_id;
  END IF;

  SELECT * INTO v_sub FROM public.tenant_subscriptions WHERE tenant_id = v_invoice.tenant_id;
  IF NOT FOUND THEN
    RAISE EXCEPTION 'Không tìm thấy subscription cho tenant: %', v_invoice.tenant_id;
  END IF;

  -- Ghi payment đã xác nhận
  INSERT INTO public.payments (
    tenant_id,
    invoice_id,
    amount,
    payment_method,
    payment_date,
    reference_code,
    status,
    notes,
    created_by
  ) VALUES (
    v_invoice.tenant_id,
    v_invoice.id,
    v_invoice.total,
    p_payment_method,
    CURRENT_DATE,
    p_reference_code,
    'confirmed',
    p_notes,
    auth.uid()
  ) RETURNING * INTO v_payment;

  -- Cập nhật hóa đơn thành paid
  UPDATE public.invoices
  SET status = 'paid',
      amount_paid = total,
      updated_at = now()
  WHERE id = p_invoice_id;

  -- Cập nhật subscription: billing_status ok, expires_at = max(hiện tại, period_end) để giữ cộng dồn
  v_new_expires_at := GREATEST(
    COALESCE(v_sub.expires_at::DATE, CURRENT_DATE),
    v_invoice.period_end::DATE
  )::TIMESTAMPTZ;

  UPDATE public.tenant_subscriptions
  SET billing_status = 'ok',
      expires_at = v_new_expires_at,
      updated_at = now()
  WHERE tenant_id = v_invoice.tenant_id;

  -- Kích hoạt lại tenant nếu đang read_only
  IF v_tenant.status = 'read_only' THEN
    UPDATE public.tenants
    SET status = 'active',
        updated_at = now()
    WHERE id = v_invoice.tenant_id;
  END IF;

  RETURN v_payment;
END;
$$;

-- === MIGRATION END: 20250706000009_phase_p7_3_payment_confirm_lifecycle.sql ===

-- === MIGRATION START: 20250706000010_phase_p7_5_expiry_renewal_cron.sql ===
-- SOURCE_PATH: C:\Users\SUACAUBA\Downloads\Project\vietsale-pro-v7\supabase\migrations\20250706000010_phase_p7_5_expiry_renewal_cron.sql
-- SIZE_BYTES: 6267
-- SHA256: A74459CC88433C7DA3F4B92C045024CE9DAA30FEB1C66BCD89B4467D1A4D2721

-- P7.5: Cron hết hạn hóa đơn + cron tạo hóa đơn gia hạn + cột giảm giá nullable cho voucher (P10).
-- ponytail: migration idempotent; cron chạy dưới quyền chủ DB nên các hàm SECURITY DEFINER và
--           KHÔNG gọi is_system_admin() (auth.uid() rỗng khi cron chạy). Mọi mốc thời gian theo Asia/Ho_Chi_Minh.

-- ============================================================
-- 0. Cột giảm giá nullable trên invoices (sẵn sàng cho voucher P10, chưa dùng ở P7)
-- ============================================================

-- ponytail: chỉ thêm cột nullable làm chỗ nối cho P10; discount (numeric) đã có sẵn.
ALTER TABLE public.invoices ADD COLUMN IF NOT EXISTS discount_code TEXT;

-- ponytail: DROP trước CREATE để đổi được kiểu trả về nếu hàm đã tồn tại từ lần thử trước.
DROP FUNCTION IF EXISTS public.expire_overdue_invoices();
DROP FUNCTION IF EXISTS public.create_renewal_invoices(INT);

-- ============================================================
-- 1. Cron: chuyển hóa đơn pending quá 48h -> expired + tenant -> read_only
-- ============================================================

CREATE OR REPLACE FUNCTION public.expire_overdue_invoices()
RETURNS INTEGER
LANGUAGE plpgsql
SECURITY DEFINER
SET search_path = public
SET timezone = 'Asia/Ho_Chi_Minh'
AS $$
DECLARE
  v_expired_count INTEGER := 0;
BEGIN
  -- ponytail: advisory lock theo tên hàm để tránh cron chạy đồng thời xử lý trùng hóa đơn.
  PERFORM pg_advisory_xact_lock(hashtextextended('expire_overdue_invoices', 0));

  -- ponytail: gộp expire invoices + cập nhật billing_status/status tenant trong một CTE để giảm race window.
  WITH expired AS (
    UPDATE public.invoices
    SET status = 'expired',
        updated_at = now()
    WHERE status = 'pending'
      AND created_at < now() - INTERVAL '48 hours'
    RETURNING tenant_id
  ),
  overdue_subs AS (
    UPDATE public.tenant_subscriptions s
    SET billing_status = 'overdue',
        updated_at = now()
    FROM expired e
    WHERE e.tenant_id = s.tenant_id
      AND s.billing_status <> 'overdue'
    RETURNING s.tenant_id
  ),
  read_only_tenants AS (
    UPDATE public.tenants t
    SET status = 'read_only',
        updated_at = now()
    FROM overdue_subs o
    WHERE o.tenant_id = t.id
      AND t.status IN ('active', 'trial')
    RETURNING t.id
  )
  SELECT count(DISTINCT tenant_id) INTO v_expired_count FROM expired;

  RETURN v_expired_count;
END;
$$;

REVOKE ALL ON FUNCTION public.expire_overdue_invoices() FROM PUBLIC;

-- ============================================================
-- 2. Cron: tạo hóa đơn gia hạn N=7 ngày trước expires_at
-- ============================================================

-- ponytail: gia hạn luôn theo chu kỳ THÁNG (1 tháng, 69k). Trần: chưa tự nhận biết khách mua năm;
--           nâng cấp sau bằng cách đọc chu kỳ gần nhất từ invoices/subscription khi cần.
CREATE OR REPLACE FUNCTION public.create_renewal_invoices(p_days_before INT DEFAULT 7)
RETURNS INTEGER
LANGUAGE plpgsql
SECURITY DEFINER
SET search_path = public
SET timezone = 'Asia/Ho_Chi_Minh'
AS $$
DECLARE
  v_sub RECORD;
  v_invoice_no TEXT;
  v_year INT;
  v_period_start DATE;
  v_period_end DATE;
  v_unit_price NUMERIC;
  v_plan public.plans%ROWTYPE;
  v_created INTEGER := 0;
  v_invoice_id UUID;
BEGIN
  IF p_days_before < 0 THEN
    RAISE EXCEPTION 'p_days_before không hợp lệ';
  END IF;

  -- ponytail: lấy đơn giá tháng từ plans; fallback nếu chưa có dữ liệu.
  SELECT * INTO v_plan FROM public.plans WHERE key = 'vip';
  v_unit_price := COALESCE(v_plan.monthly_price, 69000);

  v_year := EXTRACT(YEAR FROM CURRENT_DATE)::INT;

  -- ponytail: advisory lock để tránh 2 instance cron tạo renewal invoice trùng nhau.
  PERFORM pg_advisory_xact_lock(hashtextextended('create_renewal_invoices', 0));

  FOR v_sub IN
    SELECT s.tenant_id, s.expires_at
    FROM public.tenant_subscriptions s
    JOIN public.tenants t ON t.id = s.tenant_id
    WHERE s.plan = 'vip'
      AND s.expires_at IS NOT NULL
      AND s.expires_at::DATE >= CURRENT_DATE
      AND s.expires_at::DATE <= CURRENT_DATE + p_days_before
      AND t.status NOT IN ('archived')
      -- Chưa có hóa đơn còn mở (pending/overdue/expired) để tránh trùng.
      AND NOT EXISTS (
        SELECT 1 FROM public.invoices i
        WHERE i.tenant_id = s.tenant_id
          AND i.status IN ('pending', 'overdue', 'expired')
      )
    FOR UPDATE OF s
  LOOP
    v_period_start := v_sub.expires_at::DATE;
    v_period_end := (v_period_start + INTERVAL '1 month')::DATE;
    v_invoice_no := public.get_next_invoice_number(v_year);

    INSERT INTO public.invoices (
      tenant_id, invoice_no, status, issue_date, due_date,
      period_start, period_end, subtotal, discount, tax, total, amount_paid,
      notes, created_by
    ) VALUES (
      v_sub.tenant_id, v_invoice_no, 'pending', CURRENT_DATE, CURRENT_DATE + INTERVAL '2 days',
      v_period_start, v_period_end, v_unit_price, 0, 0, v_unit_price, 0,
      'Hóa đơn gia hạn tự động', NULL
    ) RETURNING id INTO v_invoice_id;

    INSERT INTO public.invoice_items (invoice_id, tenant_id, description, quantity, unit_price)
    VALUES (v_invoice_id, v_sub.tenant_id, 'Gói VIP - Tháng (gia hạn)', 1, v_unit_price);

    v_created := v_created + 1;
  END LOOP;

  RETURN v_created;
END;
$$;

REVOKE ALL ON FUNCTION public.create_renewal_invoices(INT) FROM PUBLIC;

-- ============================================================
-- 3. Lịch cron (pg_cron)
-- ============================================================

CREATE EXTENSION IF NOT EXISTS pg_cron;

-- ponytail: chạy hằng ngày là đủ (48h có dư biên); nếu cần nhạy hơn đổi sang mỗi giờ.
SELECT cron.schedule('invoice-expiry-daily', '30 3 * * *', 'SELECT public.expire_overdue_invoices();');
SELECT cron.schedule('renewal-invoice-daily', '0 4 * * *', 'SELECT public.create_renewal_invoices(7);');

