-- ============================================================

CREATE TABLE IF NOT EXISTS public.error_logs (
  id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
  source TEXT NOT NULL DEFAULT 'unknown',
  level TEXT NOT NULL DEFAULT 'error'
    CHECK (level IN ('error', 'warn', 'info', 'debug')),
