-- === MIGRATION START: 20260711000004_f33_members_search_rpc.sql ===
-- SOURCE_PATH: C:\Users\SUACAUBA\Downloads\Project\vietsale-pro-v7\supabase\migrations\20260711000004_f33_members_search_rpc.sql
-- SIZE_BYTES: 3163
-- SHA256: 48415AE27F067C2768CA5F48D803E163C264D2D313651DEBD42EB4142470B149

-- F33 P2: search_tenant_members RPC
-- Scope: paginated, searchable, filterable, sortable replacement for get_tenant_members_with_email.

CREATE OR REPLACE FUNCTION public.search_tenant_members(
  p_tenant_id UUID,
  p_search TEXT DEFAULT NULL,
  p_role TEXT DEFAULT NULL,
  p_status TEXT DEFAULT NULL,
  p_is_active BOOLEAN DEFAULT NULL,
  p_sort_by TEXT DEFAULT 'created_at',
  p_sort_dir TEXT DEFAULT 'desc',
  p_page INT DEFAULT 1,
  p_page_size INT DEFAULT 20
)
RETURNS json
LANGUAGE plpgsql
STABLE
SECURITY DEFINER
SET search_path = public
AS $$
DECLARE
  v_offset INT;
  v_items JSON;
  v_total_count INT;
  v_sort_by TEXT;
  v_sort_dir TEXT;
  v_search_pattern TEXT;
  v_role TEXT;
  v_status TEXT;
BEGIN
  IF NOT (public.is_system_admin() OR public.is_tenant_admin(p_tenant_id)) THEN
    RAISE EXCEPTION 'Chỉ system admin hoặc tenant admin mới được xem danh sách thành viên' USING ERRCODE = 'insufficient_privilege';
  END IF;

  v_offset := GREATEST((p_page - 1) * p_page_size, 0);
  v_search_pattern := NULLIF(trim(p_search), '');
  v_role := NULLIF(trim(p_role), '');
  v_status := NULLIF(trim(p_status), '');
  v_sort_by := CASE
    WHEN p_sort_by IN ('email', 'role', 'status', 'created_at', 'last_sign_in_at') THEN p_sort_by
    ELSE 'created_at'
  END;
  v_sort_dir := CASE WHEN lower(p_sort_dir) = 'asc' THEN 'ASC' ELSE 'DESC' END;

  SELECT COUNT(*) INTO v_total_count
  FROM public.tenant_memberships tm
  LEFT JOIN auth.users u ON u.id = tm.user_id
  WHERE tm.tenant_id = p_tenant_id
    AND (v_search_pattern IS NULL OR u.email ILIKE '%' || v_search_pattern || '%')
    AND (v_role IS NULL OR tm.role = v_role)
    AND (v_status IS NULL OR tm.status = v_status)
    AND (p_is_active IS NULL OR tm.is_active = p_is_active);

  EXECUTE format(
    'SELECT COALESCE(json_agg(row_to_json(t)), ''[]''::json)
     FROM (
       SELECT
         tm.id,
         tm.tenant_id,
         tm.user_id,
         tm.role,
         t.owner_id = tm.user_id AS is_owner,
         u.email,
         inviter.email AS invited_by_email,
         tm.status,
         tm.is_active,
         tm.invited_at,
         tm.accepted_at,
         u.last_sign_in_at,
         u.confirmed_at,
         tm.created_at,
         tm.updated_at
       FROM public.tenant_memberships tm
       JOIN public.tenants t ON t.id = tm.tenant_id
       LEFT JOIN auth.users u ON u.id = tm.user_id
       LEFT JOIN auth.users inviter ON inviter.id = tm.invited_by
       WHERE tm.tenant_id = $1
         AND ($2 IS NULL OR u.email ILIKE $2)
         AND ($3 IS NULL OR tm.role = $3)
         AND ($4 IS NULL OR tm.status = $4)
         AND ($5 IS NULL OR tm.is_active = $5)
       ORDER BY %I %s NULLS LAST
       LIMIT $6 OFFSET $7
     ) t',
    v_sort_by, v_sort_dir
  )
  INTO v_items
  USING p_tenant_id,
        CASE WHEN v_search_pattern IS NOT NULL THEN '%' || v_search_pattern || '%' ELSE NULL END,
        v_role, v_status, p_is_active,
        p_page_size, v_offset;

  RETURN jsonb_build_object(
    'items', v_items,
    'total_count', v_total_count
  );
END;
$$;

-- === MIGRATION END: 20260711000004_f33_members_search_rpc.sql ===

-- === MIGRATION START: 20260711000005_f33_members_guardrails.sql ===
-- SOURCE_PATH: C:\Users\SUACAUBA\Downloads\Project\vietsale-pro-v7\supabase\migrations\20260711000005_f33_members_guardrails.sql
-- SIZE_BYTES: 2183
-- SHA256: D1D302F179C6953BA3BF758C09BB36E4C818FE00594EECC4317E6B2DF5BB7650

-- F33 P3: Guardrails for tenant_memberships
-- Scope: protect tenant owner and last admin from deletion / role downgrade.
-- ponytail: single trigger function handles DELETE + UPDATE; SECURITY DEFINER to bypass RLS when counting remaining admins.

CREATE OR REPLACE FUNCTION public.trg_tenant_memberships_guardrails()
RETURNS TRIGGER
LANGUAGE plpgsql
SECURITY DEFINER
SET search_path = public
AS $$
DECLARE
  v_owner_id UUID;
  v_other_admins INT;
BEGIN
  SELECT owner_id INTO v_owner_id
  FROM public.tenants
  WHERE id = COALESCE(OLD.tenant_id, NEW.tenant_id);

  IF TG_OP = 'DELETE' THEN
    IF OLD.user_id = v_owner_id THEN
      RAISE EXCEPTION 'Không thể xóa owner của tenant' USING ERRCODE = 'insufficient_privilege';
    END IF;

    IF OLD.role = 'admin' THEN
      SELECT COUNT(*) INTO v_other_admins
      FROM public.tenant_memberships
      WHERE tenant_id = OLD.tenant_id
        AND role = 'admin'
        AND user_id <> OLD.user_id;

      IF v_other_admins = 0 THEN
        RAISE EXCEPTION 'Không thể xóa admin cuối cùng của tenant' USING ERRCODE = 'insufficient_privilege';
      END IF;
    END IF;

    RETURN OLD;
  END IF;

  IF TG_OP = 'UPDATE' THEN
    IF OLD.user_id = v_owner_id AND NEW.role IS DISTINCT FROM OLD.role THEN
      RAISE EXCEPTION 'Không thể đổi role của owner tenant' USING ERRCODE = 'insufficient_privilege';
    END IF;

    IF OLD.role = 'admin' AND NEW.role <> 'admin' THEN
      SELECT COUNT(*) INTO v_other_admins
      FROM public.tenant_memberships
      WHERE tenant_id = OLD.tenant_id
        AND role = 'admin'
        AND user_id <> OLD.user_id;

      IF v_other_admins = 0 THEN
        RAISE EXCEPTION 'Không thể hạ role admin cuối cùng của tenant' USING ERRCODE = 'insufficient_privilege';
      END IF;
    END IF;

    RETURN NEW;
  END IF;

  RETURN NULL;
END;
$$;

DROP TRIGGER IF EXISTS tenant_memberships_guardrails ON public.tenant_memberships;

CREATE TRIGGER tenant_memberships_guardrails
BEFORE DELETE OR UPDATE ON public.tenant_memberships
FOR EACH ROW
EXECUTE FUNCTION public.trg_tenant_memberships_guardrails();

-- === MIGRATION END: 20260711000005_f33_members_guardrails.sql ===

