-- SOURCE_PATH: C:\Users\SUACAUBA\Downloads\Project\vietsale-pro-v7\supabase\migrations\20260712000010_fix_get_tenant_usage_summary_tenant_admin.sql
-- SIZE_BYTES: 2737
-- SHA256: 1DA3681D6DBD57A6780BC748BDB9AABAED1AA887549D2E35B898603057840E87

-- Migration: 20260712000010_fix_get_tenant_usage_summary_tenant_admin.sql
-- Fix: cho phép tenant admin gọi get_tenant_usage_summary

CREATE OR REPLACE FUNCTION public.get_tenant_usage_summary(p_tenant_id UUID)
RETURNS JSON
LANGUAGE plpgsql
STABLE
SECURITY INVOKER
AS $$
DECLARE
  v_user_count INTEGER;
  v_product_count INTEGER;
  v_sub public.tenant_subscriptions%ROWTYPE;
  v_tenant public.tenants%ROWTYPE;
  v_current_month_orders INTEGER;
  v_current_month_start DATE;
  v_today DATE;
BEGIN
  -- FIX [5.6]: Cho phép cả system admin và tenant admin
  IF NOT (public.is_system_admin() OR public.is_tenant_admin(p_tenant_id)) THEN
    RAISE EXCEPTION 'Chỉ system admin hoặc tenant admin mới được xem usage tenant' USING ERRCODE = 'insufficient_privilege';
  END IF;

  SELECT * INTO v_tenant FROM public.tenants WHERE id = p_tenant_id;
  IF NOT FOUND THEN
    RAISE EXCEPTION 'Không tìm thấy tenant: %', p_tenant_id;
  END IF;

  SELECT * INTO v_sub FROM public.tenant_subscriptions WHERE tenant_id = p_tenant_id;
  IF NOT FOUND THEN
    RAISE EXCEPTION 'Không tìm thấy subscription cho tenant: %', p_tenant_id;
  END IF;

  SELECT COUNT(*) INTO v_user_count
  FROM public.tenant_memberships
  WHERE tenant_id = p_tenant_id AND status IN ('pending', 'active');

  SELECT COUNT(*) INTO v_product_count FROM public.products WHERE tenant_id = p_tenant_id;

  v_today := date_trunc('month', CURRENT_DATE)::DATE;
  v_current_month_start := v_sub.current_month_start;
  IF v_current_month_start IS NULL OR v_current_month_start <> v_today THEN
    v_current_month_orders := 0;
    v_current_month_start := v_today;
  ELSE
    v_current_month_orders := v_sub.current_month_orders;
  END IF;

  RETURN json_build_object(
    'tenantId', v_sub.tenant_id,
    'plan', v_sub.plan,
    'billingStatus', v_sub.billing_status,
    'expiresAt', v_sub.expires_at,
    'users', json_build_object(
      'current', v_user_count,
      'max', v_sub.max_users,
      'percent', CASE WHEN v_sub.max_users > 0 THEN ROUND((v_user_count::NUMERIC / v_sub.max_users) * 100, 2) ELSE 0 END
    ),
    'products', json_build_object(
      'current', v_product_count,
      'max', v_sub.max_products,
      'percent', CASE WHEN v_sub.max_products > 0 THEN ROUND((v_product_count::NUMERIC / v_sub.max_products) * 100, 2) ELSE 0 END
    ),
    'orders', json_build_object(
      'current', v_current_month_orders,
      'max', v_sub.max_orders_per_month,
      'percent', CASE WHEN v_sub.max_orders_per_month > 0 THEN ROUND((v_current_month_orders::NUMERIC / v_sub.max_orders_per_month) * 100, 2) ELSE 0 END,
      'monthStart', v_current_month_start
    )
  );
END;
$$;

-- === MIGRATION END: 20260712000010_fix_get_tenant_usage_summary_tenant_admin.sql ===

-- === MIGRATION START: 20260712000011_fix_is_system_admin_service_role.sql ===
-- SOURCE_PATH: C:\Users\SUACAUBA\Downloads\Project\vietsale-pro-v7\supabase\migrations\20260712000011_fix_is_system_admin_service_role.sql
-- SIZE_BYTES: 844
-- SHA256: 195A152A73D4851D7B1F0FF1CA965B1D436309B0BF0BF73CE4A5028B00023921

-- Migration: 20260712000011_fix_is_system_admin_service_role.sql
-- Fix: is_system_admin() returns false when called from service-role context
-- because auth.uid() is null for service_role clients.
--
-- Root cause: is_system_admin() uses SECURITY DEFINER and checks auth.uid().
-- When Edge Functions call RPCs via service-role client, auth.uid() is null,
-- causing is_system_admin() to return false even for valid operations.
--
-- Fix: Allow service_role to bypass the check (service_role is trusted by definition).

CREATE OR REPLACE FUNCTION public.is_system_admin()
RETURNS BOOLEAN
LANGUAGE sql
STABLE
SECURITY DEFINER
SET search_path = public
AS $$
  SELECT
    CASE
      WHEN current_user = 'service_role' THEN true
      ELSE EXISTS (SELECT 1 FROM public.system_admins WHERE user_id = auth.uid())
    END;
$$;

-- === MIGRATION END: 20260712000011_fix_is_system_admin_service_role.sql ===

-- === MIGRATION START: 20260712000012_add_system_admin_for_edge.sql ===
-- SOURCE_PATH: C:\Users\SUACAUBA\Downloads\Project\vietsale-pro-v7\supabase\migrations\20260712000012_add_system_admin_for_edge.sql
-- SIZE_BYTES: 2790
-- SHA256: A34249CB8361D60B957FB03E240ADC4C9856F22A4AEDDFC76640BF4F1E6D4F08

-- Migration: 20260712000012_add_system_admin_for_edge.sql
-- RPC dành riêng cho Edge Function (không check auth.uid())
--
-- Lý do: Khi Edge Function gọi RPC từ service-role client, auth.uid() là null.
-- is_system_admin() đã được fix (migration 00011) để cho phép service_role bypass,
-- nhưng add_system_admin() cũng bị lỗi tương tự: nó kiểm tra caller là system admin
-- dựa trên auth.uid(), nhưng service-role client không có auth.uid().
--
-- Cách 1 (Trong EF main handler - đã done ở migration 00011):
--   is_system_admin() cho phép current_user = 'service_role' bypass
--
-- Cách 2 (RPC riêng cho Edge Function - migration này):
--   Tạo RPC add_system_admin_for_edge chỉ cho phép service_role gọi,
--   nhận p_creator_id để audit log, không dùng auth.uid()
--
-- Cách 3 (Direct insert trong EF - đã dùng trong create-system-admin):
--   supabaseAdmin.from('system_admins').insert({ user_id: newUserId })
--
-- Migration này implement Cách 2 để các Edge Function khác có thể gọi RPC
-- thay vì direct insert (có validation + audit log đầy đủ)

CREATE OR REPLACE FUNCTION public.add_system_admin_for_edge(
  p_user_id UUID,
  p_creator_id UUID
)
RETURNS public.system_admins
LANGUAGE plpgsql
SECURITY DEFINER
SET search_path = public
AS $$
DECLARE
  v_row public.system_admins;
BEGIN
  -- Chỉ cho phép service_role gọi RPC này
  IF current_user != 'service_role' THEN
    RAISE EXCEPTION 'Only service_role can call this function' USING ERRCODE = 'insufficient_privilege';
  END IF;

  -- Validate user exists
  IF NOT EXISTS (SELECT 1 FROM auth.users WHERE id = p_user_id) THEN
    RAISE EXCEPTION 'Không tìm thấy user: %', p_user_id;
  END IF;

  -- Check not already system admin
  IF EXISTS (SELECT 1 FROM public.system_admins WHERE user_id = p_user_id) THEN
    RAISE EXCEPTION 'User already a system admin';
  END IF;

  -- Insert new system admin
  INSERT INTO public.system_admins (user_id)
  VALUES (p_user_id)
  RETURNING * INTO v_row;

  -- Audit log
  INSERT INTO public.app_audit_log (user_id, table_name, record_id, action, new_data)
  VALUES (p_creator_id, 'system_admins', p_user_id, 'SYSTEM_ADMIN_ADD',
          jsonb_build_object('new_admin_id', p_user_id, 'created_by', p_creator_id));

  RETURN v_row;
END;
$$;

-- Thêm comment cho RPC
COMMENT ON FUNCTION public.add_system_admin_for_edge IS 
'RPC dành riêng cho Edge Function (service_role) để thêm system admin.
Không sử dụng auth.uid() vì service_role client không có auth.uid().
Caller phải truyền p_creator_id là UUID của system admin đang thực hiện hành động.
Chỉ service_role mới được gọi RPC này.';

-- === MIGRATION END: 20260712000012_add_system_admin_for_edge.sql ===

-- === MIGRATION START: 20260712000013_add_viewer_role.sql ===
-- SOURCE_PATH: C:\Users\SUACAUBA\Downloads\Project\vietsale-pro-v7\supabase\migrations\20260712000013_add_viewer_role.sql
-- SIZE_BYTES: 3651
-- SHA256: F8953DD55F22720F50BA89E8B7B49426DF9AE04576CF3E83F844B91F44141AFB

-- FIX [6.4]: Add 'viewer' role to all RPC role validations
-- Migration: 20260712000013_add_viewer_role.sql

-- 1. Update update_tenant_member_role to accept 'viewer'
CREATE OR REPLACE FUNCTION public.update_tenant_member_role(
  p_tenant_id UUID,
  p_user_id UUID,
  p_role TEXT
) RETURNS public.tenant_memberships
LANGUAGE plpgsql
SECURITY DEFINER
SET search_path = public
AS $$
DECLARE
  v_caller_id UUID;
  v_caller_role TEXT;
  v_old_role TEXT;
  v_admin_count INT;
  v_is_owner BOOLEAN;
  v_row public.tenant_memberships;
BEGIN
  v_caller_id := auth.uid();
  
  -- Guard 1: Authenticated
  IF v_caller_id IS NULL THEN
    RAISE EXCEPTION 'Yêu cầu xác thực' USING ERRCODE = 'insufficient_privilege';
  END IF;
  
  -- Guard 2: Validate role (FIX [6.4]: added 'viewer')
  IF p_role NOT IN ('admin', 'cashier', 'inventory_manager', 'accountant', 'viewer') THEN
    RAISE EXCEPTION 'Vai trò không hợp lệ. Chỉ chấp nhận: admin, cashier, inventory_manager, accountant, viewer' USING ERRCODE = 'check_violation';
  END IF;
  
  -- Guard 3: Check caller authorization
  IF NOT EXISTS (SELECT 1 FROM public.system_admins WHERE user_id = v_caller_id) THEN
    SELECT role INTO v_caller_role
    FROM public.tenant_memberships
    WHERE tenant_id = p_tenant_id AND user_id = v_caller_id;
    
    IF v_caller_role IS NULL OR v_caller_role != 'admin' THEN
      RAISE EXCEPTION 'Chỉ admin của tenant hoặc system admin được đổi vai trò' USING ERRCODE = 'insufficient_privilege';
    END IF;
  END IF;
  
  -- Guard 4: Self-demote guard
  IF v_caller_id = p_user_id THEN
    RAISE EXCEPTION 'Không thể tự đổi vai trò của chính mình' USING ERRCODE = 'insufficient_privilege';
  END IF;
  
  -- Guard 5: Get current role and owner status
  SELECT tm.role, (t.owner_id = p_user_id) INTO v_old_role, v_is_owner
  FROM public.tenant_memberships tm
  JOIN public.tenants t ON t.id = tm.tenant_id
  WHERE tm.tenant_id = p_tenant_id AND tm.user_id = p_user_id;
  
  IF v_old_role IS NULL THEN
    RAISE EXCEPTION 'Thành viên không tồn tại trong tenant này' USING ERRCODE = 'no_data_found';
  END IF;
  
  -- Guard 6: Cannot change owner's role
  IF v_is_owner THEN
    RAISE EXCEPTION 'Không thể đổi vai trò của chủ sở hữu tenant' USING ERRCODE = 'insufficient_privilege';
  END IF;
  
  -- Guard 7: If demoting from admin, check last admin (chỉ tính active + is_active = true)
  IF v_old_role = 'admin' AND p_role != 'admin' THEN
    SELECT COUNT(*) INTO v_admin_count
    FROM public.tenant_memberships
    WHERE tenant_id = p_tenant_id 
      AND role = 'admin' 
      AND user_id != p_user_id
      AND status IN ('active', 'pending')
      AND is_active = true;
    
    IF v_admin_count = 0 THEN
      RAISE EXCEPTION 'Không thể hạ role admin duy nhất của tenant' USING ERRCODE = 'insufficient_privilege';
    END IF;
  END IF;
  
  -- Execute update
  UPDATE public.tenant_memberships
  SET role = p_role, updated_at = now()
  WHERE tenant_id = p_tenant_id AND user_id = p_user_id
  RETURNING * INTO v_row;
  
  -- Audit log
  INSERT INTO public.app_audit_log (tenant_id, user_id, table_name, record_id, action, old_data, new_data, ip_address)
  VALUES (p_tenant_id, v_caller_id, 'tenant_memberships', p_user_id, 'MEMBER_ROLE_CHANGE', 
          jsonb_build_object('old_role', v_old_role, 'new_role', p_role),
          jsonb_build_object('old_role', v_old_role, 'new_role', p_role),
          current_setting('request.headers')::jsonb->>'x-forwarded-for');
  
  RETURN v_row;
END;
$$;

-- === MIGRATION END: 20260712000013_add_viewer_role.sql ===

-- === MIGRATION START: 20260712101730_sp3_4_usage_metering.sql ===
-- SOURCE_PATH: C:\Users\SUACAUBA\Downloads\Project\vietsale-pro-v7\supabase\migrations\20260712101730_sp3_4_usage_metering.sql
-- SIZE_BYTES: 2229
-- SHA256: 09A86DD98475387A657C99382C49D23AC5DA0269B0A72D60B04F1F0445810B95

-- SP-3.4: Usage metering
-- ponytail: idempotent migration adding tenant_usage_records table with tenant isolation.
--          Service summarises client-side; ceiling is O(n) per tenant/metric, upgrade path is a DB aggregate RPC.

-- ============================================================
-- 1. Bảng usage records
-- ============================================================

CREATE TABLE IF NOT EXISTS public.tenant_usage_records (
  id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
  tenant_id UUID NOT NULL REFERENCES public.tenants(id) ON DELETE CASCADE,
  metric_key TEXT NOT NULL,
  quantity NUMERIC(12,4) NOT NULL DEFAULT 1 CHECK (quantity >= 0),
  source TEXT,
  metadata JSONB,
  recorded_at TIMESTAMPTZ NOT NULL DEFAULT now(),
  created_at TIMESTAMPTZ NOT NULL DEFAULT now()
);

CREATE INDEX IF NOT EXISTS idx_tenant_usage_records_lookup
  ON public.tenant_usage_records (tenant_id, metric_key, recorded_at DESC);

COMMENT ON TABLE public.tenant_usage_records IS 'Granular usage events per tenant for metering and quota tracking.';

-- ============================================================
-- 2. RLS policies (tenant isolation + system admin bypass)
-- ============================================================

ALTER TABLE public.tenant_usage_records ENABLE ROW LEVEL SECURITY;

DO $$
BEGIN
  IF NOT EXISTS (
    SELECT 1 FROM pg_policies
    WHERE schemaname = 'public' AND tablename = 'tenant_usage_records' AND policyname = 'tenant_usage_records_select'
  ) THEN
    CREATE POLICY "tenant_usage_records_select"
      ON public.tenant_usage_records FOR SELECT TO authenticated
      USING (public.is_system_admin() OR (tenant_id = public.current_tenant_id() AND public.is_tenant_member(tenant_id)));
  END IF;

  IF NOT EXISTS (
    SELECT 1 FROM pg_policies
    WHERE schemaname = 'public' AND tablename = 'tenant_usage_records' AND policyname = 'tenant_usage_records_insert'
  ) THEN
    CREATE POLICY "tenant_usage_records_insert"
      ON public.tenant_usage_records FOR INSERT TO authenticated
      WITH CHECK (public.is_system_admin() OR (tenant_id = public.current_tenant_id() AND public.is_tenant_member(tenant_id)));
  END IF;
END $$;

-- === MIGRATION END: 20260712101730_sp3_4_usage_metering.sql ===

-- === MIGRATION START: 20260712140000_sp1_4_missing_rls_policies.sql ===
-- SOURCE_PATH: C:\Users\SUACAUBA\Downloads\Project\vietsale-pro-v7\supabase\migrations\20260712140000_sp1_4_missing_rls_policies.sql
-- SIZE_BYTES: 6687
-- SHA256: A79795BFF0BBBE6982C5D548FAB36CF25D758F1D29B4B4F62D7DA52661B87B54

-- SP-1.4: Add missing RLS policies
-- Source: docs/rls-gap-analysis.md
-- ponytail: idempotent; enable RLS and add policies only when they do not already exist.

-- ============================================================================
-- 1. Tenant-scoped tables missing RLS
-- ============================================================================

DO $$
DECLARE
  tbl TEXT;
BEGIN
  FOREACH tbl IN ARRAY ARRAY['tenant_restore_snapshots', 'orders_archive', 'order_items_archive', 'app_audit_log_partitioned']
  LOOP
    IF EXISTS (SELECT 1 FROM pg_tables WHERE schemaname = 'public' AND tablename = tbl) THEN
      EXECUTE format('ALTER TABLE public.%I ENABLE ROW LEVEL SECURITY', tbl);
    END IF;
  END LOOP;
END $$;

-- tenant_restore_snapshots: tenant members view their own snapshots; system admins bypass.
-- ponytail: snapshots are created only by the SECURITY DEFINER restore RPC; no client writes.
DO $$
BEGIN
  IF EXISTS (SELECT 1 FROM pg_tables WHERE schemaname = 'public' AND tablename = 'tenant_restore_snapshots') THEN
    IF NOT EXISTS (
      SELECT 1 FROM pg_policies
      WHERE schemaname = 'public' AND tablename = 'tenant_restore_snapshots' AND policyname = 'tenant_restore_snapshots_select'
    ) THEN
      CREATE POLICY "tenant_restore_snapshots_select" ON public.tenant_restore_snapshots FOR SELECT TO authenticated
        USING ((tenant_id = public.current_tenant_id() AND public.is_tenant_member(tenant_id)) OR public.is_system_admin());
    END IF;
  END IF;
END $$;

-- orders_archive / order_items_archive: tenant members read-only archives.
DO $$
DECLARE
  tbl TEXT;
BEGIN
  FOREACH tbl IN ARRAY ARRAY['orders_archive', 'order_items_archive']
  LOOP
    IF EXISTS (SELECT 1 FROM pg_tables WHERE schemaname = 'public' AND tablename = tbl) THEN
      IF NOT EXISTS (
        SELECT 1 FROM pg_policies
        WHERE schemaname = 'public' AND tablename = tbl AND policyname = tbl || '_select'
      ) THEN
        EXECUTE format(
          'CREATE POLICY %I ON public.%I FOR SELECT TO authenticated '
          'USING ((tenant_id = public.current_tenant_id() AND public.is_tenant_member(tenant_id)) OR public.is_system_admin())',
          tbl || '_select', tbl
        );
      END IF;
    END IF;
  END LOOP;
END $$;

-- app_audit_log_partitioned: mirror app_audit_log policy (tenant admin or system admin).
DO $$
BEGIN
  IF EXISTS (SELECT 1 FROM pg_tables WHERE schemaname = 'public' AND tablename = 'app_audit_log_partitioned') THEN
    IF NOT EXISTS (
      SELECT 1 FROM pg_policies
