-- === MIGRATION START: 20260713000001_standardize_tenants_and_memberships.sql ===
-- SOURCE_PATH: C:\Users\SUACAUBA\Downloads\Project\vietsale-pro-v7\supabase\migrations\20260713000001_standardize_tenants_and_memberships.sql
-- SIZE_BYTES: 3060
-- SHA256: 8701AD069B6EE37FAAC29A2860B0754986413136A8D34A2E9E6B424154EB751A

-- Sub-Phase 3.1: Standardize tenants/tenant_memberships per Basejump account model
-- Scope: add owner role + user tracking columns + personal account flag; backfill existing owners.
-- ponytail: additive changes only; safe to re-run.

-- ============================================================
-- 1. Standardize tenants: add Basejump tracking columns + personal account flag
-- ============================================================

ALTER TABLE public.tenants
ADD COLUMN IF NOT EXISTS created_by UUID REFERENCES auth.users(id) ON DELETE SET NULL,
ADD COLUMN IF NOT EXISTS updated_by UUID REFERENCES auth.users(id) ON DELETE SET NULL,
ADD COLUMN IF NOT EXISTS is_personal BOOLEAN NOT NULL DEFAULT false;

-- ponytail: add Basejump `slug` as a generated alias of existing `subdomain` to avoid a rename migration.
ALTER TABLE public.tenants
ADD COLUMN IF NOT EXISTS slug TEXT GENERATED ALWAYS AS (subdomain) STORED;

-- ============================================================
-- 2. Backfill created_by/updated_by from existing owner_id
-- ============================================================

UPDATE public.tenants
SET created_by = owner_id,
    updated_by = owner_id
WHERE created_by IS NULL
  AND owner_id IS NOT NULL;

-- ============================================================
-- 3. Expand tenant_memberships role enum to include owner and viewer
-- ============================================================

ALTER TABLE public.tenant_memberships
DROP CONSTRAINT IF EXISTS tenant_memberships_role_check;

ALTER TABLE public.tenant_memberships
ADD CONSTRAINT tenant_memberships_role_check
CHECK (role IN ('owner', 'admin', 'cashier', 'inventory_manager', 'accountant', 'viewer'));

-- ============================================================
-- 4. Ensure every tenant owner has an active owner membership
-- ============================================================

-- ponytail: temporarily disable guardrail + audit triggers; backfill legitimately assigns owner role
-- and legacy audit trigger may use disallowed MEMBER_* action values on production.
ALTER TABLE public.tenant_memberships DISABLE TRIGGER tenant_memberships_guardrails;
ALTER TABLE public.tenant_memberships DISABLE TRIGGER tenant_memberships_audit;

-- Insert missing owner memberships for tenants that only store owner_id
INSERT INTO public.tenant_memberships (tenant_id, user_id, role, status, is_active, invited_at, accepted_at)
SELECT t.id, t.owner_id, 'owner', 'active', true, now(), now()
FROM public.tenants t
WHERE t.owner_id IS NOT NULL
  AND NOT EXISTS (
    SELECT 1 FROM public.tenant_memberships tm
    WHERE tm.tenant_id = t.id AND tm.user_id = t.owner_id
  );

-- Promote existing owner rows to the owner role
UPDATE public.tenant_memberships tm
SET role = 'owner'
FROM public.tenants t
WHERE tm.tenant_id = t.id
  AND tm.user_id = t.owner_id
  AND tm.role != 'owner';

ALTER TABLE public.tenant_memberships ENABLE TRIGGER tenant_memberships_audit;
ALTER TABLE public.tenant_memberships ENABLE TRIGGER tenant_memberships_guardrails;

-- === MIGRATION END: 20260713000001_standardize_tenants_and_memberships.sql ===

-- === MIGRATION START: 20260713000003_create_rls_helper_functions.sql ===
-- SOURCE_PATH: C:\Users\SUACAUBA\Downloads\Project\vietsale-pro-v7\supabase\migrations\20260713000003_create_rls_helper_functions.sql
-- SIZE_BYTES: 1786
-- SHA256: A36BA5F3209DBCD8C78AC1CA4B58EC3653B6809277881E17707C9600F411D476

-- Sub-Phase 3.1: RLS helper functions
-- Basejump reference: Section 3.2
-- ponytail: SECURITY DEFINER + STABLE so these can be used inside RLS policies.

-- ============================================================
-- 1. has_tenant_role: current user has a specific role on a tenant
-- ============================================================

CREATE OR REPLACE FUNCTION public.has_tenant_role(p_tenant_id UUID, p_role TEXT)
RETURNS BOOLEAN
LANGUAGE sql
STABLE
SECURITY DEFINER
SET search_path = public
AS $$
  SELECT EXISTS (
    SELECT 1
    FROM public.tenant_memberships
    WHERE tenant_id = p_tenant_id
      AND user_id = auth.uid()
      AND role = p_role
  );
$$;

-- ============================================================
-- 2. get_tenants_for_user: tenant IDs the current user belongs to
-- ============================================================

CREATE OR REPLACE FUNCTION public.get_tenants_for_user(p_role TEXT DEFAULT NULL)
RETURNS SETOF UUID
LANGUAGE sql
STABLE
SECURITY DEFINER
SET search_path = public
AS $$
  SELECT tenant_id
  FROM public.tenant_memberships
  WHERE user_id = auth.uid()
    AND (p_role IS NULL OR role = p_role);
$$;

-- ============================================================
-- 3. is_tenant_owner: current user owns the tenant
-- ============================================================

CREATE OR REPLACE FUNCTION public.is_tenant_owner(p_tenant_id UUID)
RETURNS BOOLEAN
LANGUAGE sql
STABLE
SECURITY DEFINER
SET search_path = public
AS $$
  SELECT EXISTS (
    SELECT 1
    FROM public.tenant_memberships
    WHERE tenant_id = p_tenant_id
      AND user_id = auth.uid()
      AND role = 'owner'
  ) OR EXISTS (
    SELECT 1
    FROM public.tenants
    WHERE id = p_tenant_id
      AND owner_id = auth.uid()
  );
$$;

-- === MIGRATION END: 20260713000003_create_rls_helper_functions.sql ===

-- === MIGRATION START: 20260713000004_create_user_tracking_triggers.sql ===
-- SOURCE_PATH: C:\Users\SUACAUBA\Downloads\Project\vietsale-pro-v7\supabase\migrations\20260713000004_create_user_tracking_triggers.sql
-- SIZE_BYTES: 2321
-- SHA256: 4D4A0EAE223B6180ACA0B956446B14A7B3D40A7300712636FBCBD4A7078ADB71

-- Sub-Phase 3.1: User tracking triggers
-- Basejump reference: Section 3.4 (personal tenant), 3.5 (user tracking)
-- ponytail: SECURITY DEFINER so the triggers can write user tracking regardless of caller RLS.

-- ============================================================
-- 1. Set created_by/updated_by on tenants
-- ============================================================

CREATE OR REPLACE FUNCTION public.set_tenant_record_user_tracking()
RETURNS TRIGGER
LANGUAGE plpgsql
SECURITY DEFINER
SET search_path = public
AS $$
BEGIN
  IF TG_OP = 'INSERT' THEN
    NEW.created_by := COALESCE(NEW.created_by, auth.uid());
    NEW.updated_by := COALESCE(NEW.updated_by, auth.uid());
  ELSIF TG_OP = 'UPDATE' THEN
    NEW.updated_by := COALESCE(NEW.updated_by, auth.uid());
  END IF;
  RETURN NEW;
END;
$$;

DROP TRIGGER IF EXISTS set_tenant_record_user_tracking ON public.tenants;
CREATE TRIGGER set_tenant_record_user_tracking
  BEFORE INSERT OR UPDATE ON public.tenants
  FOR EACH ROW
  EXECUTE FUNCTION public.set_tenant_record_user_tracking();

-- ============================================================
-- 2. Auto-create a personal tenant + owner membership for every new user
-- ============================================================

CREATE OR REPLACE FUNCTION public.handle_new_user()
RETURNS TRIGGER
LANGUAGE plpgsql
SECURITY DEFINER
SET search_path = public
AS $$
DECLARE
  v_tenant_id UUID;
  v_subdomain TEXT;
  v_name TEXT;
BEGIN
  v_name := COALESCE(NEW.raw_user_meta_data->>'name', NEW.email, 'User');
  v_subdomain := 'personal-' || lower(regexp_replace(split_part(COALESCE(NEW.email, 'user'), '@', 1), '[^a-z0-9]', '-', 'g')) || '-' || substr(NEW.id::text, 1, 8);

  INSERT INTO public.tenants (name, subdomain, status, plan, owner_id, settings, is_personal, created_by, updated_by)
  VALUES (v_name, v_subdomain, 'active', 'free', NEW.id, '{}'::jsonb, true, NEW.id, NEW.id)
  RETURNING id INTO v_tenant_id;

  INSERT INTO public.tenant_memberships (tenant_id, user_id, role, status, is_active, invited_at, accepted_at)
  VALUES (v_tenant_id, NEW.id, 'owner', 'active', true, now(), now());

  RETURN NEW;
END;
$$;

DROP TRIGGER IF EXISTS handle_new_user ON auth.users;
CREATE TRIGGER handle_new_user
  AFTER INSERT ON auth.users
  FOR EACH ROW
  EXECUTE FUNCTION public.handle_new_user();

-- === MIGRATION END: 20260713000004_create_user_tracking_triggers.sql ===

