-- ============================================================

ALTER TABLE public.tenants ENABLE ROW LEVEL SECURITY;
ALTER TABLE public.tenant_memberships ENABLE ROW LEVEL SECURITY;

-- ============================================================
-- 2. Drop old conflicting policies (replaced by Basejump pattern below)
-- ============================================================

