-- SOURCE_PATH: C:\Users\SUACAUBA\Downloads\Project\vietsale-pro-v7\supabase\migrations\20260713000009_create_plan_features.sql
-- SIZE_BYTES: 2826
-- SHA256: B2EA1CB4F0CBA22A8966DF59678AC8293B22922149275EB0B7223B52951DEA08

-- Sub-Phase 4.2: Feature gating schema
-- Basejump reference: Section 3.7 (can_use_feature, plan_features table)
-- ponytail: migration idempotent; defaults to allowing features when no gating row exists.

-- ============================================================
-- 1. plan_features table
-- ============================================================

CREATE TABLE IF NOT EXISTS public.plan_features (
  id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
  plan_id TEXT NOT NULL REFERENCES public.plans(key) ON DELETE CASCADE,
  feature_key TEXT NOT NULL,
  enabled BOOLEAN NOT NULL DEFAULT true,
  limit_value INTEGER,
  created_at TIMESTAMPTZ NOT NULL DEFAULT now(),
  updated_at TIMESTAMPTZ NOT NULL DEFAULT now(),
  UNIQUE (plan_id, feature_key)
);

CREATE INDEX IF NOT EXISTS plan_features_plan_id_idx ON public.plan_features(plan_id);
CREATE INDEX IF NOT EXISTS plan_features_feature_key_idx ON public.plan_features(feature_key);

-- ============================================================
-- 2. can_use_feature function
-- ============================================================

CREATE OR REPLACE FUNCTION public.can_use_feature(
  p_tenant_id UUID,
  p_feature_key TEXT,
  p_current_usage INTEGER DEFAULT 0
)
RETURNS BOOLEAN
LANGUAGE plpgsql
SECURITY DEFINER
SET search_path = public
AS $$
DECLARE
  v_plan_id TEXT;
  v_feature public.plan_features%ROWTYPE;
BEGIN
  -- Find the tenant's current plan from the subscription record.
  SELECT plan_id INTO v_plan_id
  FROM public.tenant_subscriptions
  WHERE tenant_id = p_tenant_id
  LIMIT 1;

  -- If no plan is found, default to allowing the feature (graceful degradation).
  IF v_plan_id IS NULL THEN
    RETURN true;
  END IF;

  SELECT * INTO v_feature
  FROM public.plan_features
  WHERE plan_id = v_plan_id
    AND feature_key = p_feature_key;

  -- If no gating row exists for this feature, default to allowing it.
  IF NOT FOUND THEN
    RETURN true;
  END IF;

  -- Feature explicitly disabled.
  IF NOT v_feature.enabled THEN
    RETURN false;
  END IF;

  -- Feature limit exceeded (inclusive).
  IF v_feature.limit_value IS NOT NULL AND p_current_usage >= v_feature.limit_value THEN
    RETURN false;
  END IF;

  RETURN true;
END;
$$;

-- ============================================================
-- 3. Trigger to keep updated_at in sync
-- ============================================================

CREATE OR REPLACE FUNCTION public.update_plan_features_updated_at()
RETURNS TRIGGER
LANGUAGE plpgsql
SECURITY DEFINER
SET search_path = public
AS $$
BEGIN
  NEW.updated_at = now();
  RETURN NEW;
END;
$$;

DROP TRIGGER IF EXISTS plan_features_updated_at ON public.plan_features;
CREATE TRIGGER plan_features_updated_at
  BEFORE UPDATE ON public.plan_features
  FOR EACH ROW
  EXECUTE FUNCTION public.update_plan_features_updated_at();

-- === MIGRATION END: 20260713000009_create_plan_features.sql ===

-- === MIGRATION START: 20260713000010_add_role_enum.sql ===
-- SOURCE_PATH: C:\Users\SUACAUBA\Downloads\Project\vietsale-pro-v7\supabase\migrations\20260713000010_add_role_enum.sql
-- SIZE_BYTES: 1737
-- SHA256: AF4412FD5A8E4D53A8CD59CA4FEAF0D464CDFE5301C573A5B87F94DAE11B5C1F

-- Sub-Phase 5.1: Role enum for tenant RBAC
-- Basejump reference: tenant_role enum
-- ponytail: idempotent DDL; keeps existing POS-specific roles (cashier, inventory_manager,
-- accountant) working by leaving tenant_memberships.role as text when incompatible values exist.

DO $$ BEGIN
  CREATE TYPE public.tenant_role AS ENUM ('owner', 'admin', 'member', 'viewer');
EXCEPTION WHEN duplicate_object THEN NULL;
END $$;

ALTER TABLE public.tenant_memberships
  ADD COLUMN IF NOT EXISTS role public.tenant_role NOT NULL DEFAULT 'member';

-- Drop the old text CHECK constraint before attempting a type coercion; otherwise
-- the ALTER TYPE step fails comparing the enum column to text literals.
ALTER TABLE public.tenant_memberships
  DROP CONSTRAINT IF EXISTS tenant_memberships_role_check;

-- ponytail: only coerce an existing text/varchar role column to the enum when every value
-- already fits the enum. If the tenant has legacy POS roles, we keep text to avoid data loss.
DO $$
DECLARE
  v_col_type TEXT;
BEGIN
  SELECT data_type INTO v_col_type
  FROM information_schema.columns
  WHERE table_schema = 'public'
    AND table_name = 'tenant_memberships'
    AND column_name = 'role';

  IF v_col_type = 'USER-DEFINED' THEN
    RETURN;
  END IF;

  IF v_col_type IN ('character varying', 'text') THEN
    IF EXISTS (
      SELECT 1
      FROM public.tenant_memberships
      WHERE role IS NOT NULL
        AND role NOT IN ('owner', 'admin', 'member', 'viewer')
    ) THEN
      RAISE NOTICE 'tenant_memberships.role contains non-enum values; leaving as text';
      RETURN;
    END IF;

    ALTER TABLE public.tenant_memberships
      ALTER COLUMN role TYPE public.tenant_role
      USING role::public.tenant_role;
  END IF;
END $$;

-- === MIGRATION END: 20260713000010_add_role_enum.sql ===

