    OR public.is_system_admin()
  );

DROP POLICY IF EXISTS invitations_insert_for_admins ON public.invitations;
CREATE POLICY invitations_insert_for_admins
  ON public.invitations FOR INSERT TO authenticated
  WITH CHECK (
