LANGUAGE plpgsql
SECURITY DEFINER
SET search_path = public
SET timezone = 'UTC'
AS $$
DECLARE
  v_value JSONB;
BEGIN
  SELECT value INTO v_value FROM public.system_settings WHERE key = 'admin_cron_config';
  IF v_value IS NULL THEN
    RETURN jsonb_build_object(
      'enabled', true,
      'function_url', '',
