-- SOURCE_PATH: C:\Users\SUACAUBA\Downloads\Project\vietsale-pro-v7\supabase\migrations\20260723000001_g1_add_max_storage_gb_to_tenant_subscriptions.sql
-- SIZE_BYTES: 4093
